import type { Drill } from "./types";

// Engineer / early drills, keyed by module slug — 25 per module.
// Early-career IC software engineer with no reports: standups, PRs, code review,
// bug reports, incident channels, estimates, on-call handoffs. Merged into course.ts.
export const ENGINEER_EARLY_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-eng-early-01","level":"early","profession":"engineer","title":"The debugging-saga standup","scenario":"You spent two days chasing a memory leak in the image-processing worker and finally found it: an unclosed stream in the retry path. The fix is up for review. Your instinct is to walk the team through every dead end before saying so.","task":"Write a 1-2 sentence standup update that leads with the outcome.","tips":["First words: found it, fix in review.","The dead ends are a coffee-break story, not standup material.","End with the one thing you need — a reviewer."],"focus":["concision","structure"],"placeholder":"Found the memory leak — unclosed stream in the retry path. Fix is in review; could use eyes today."},
    {"id":"lead-eng-early-02","level":"early","profession":"engineer","title":"The flaky-test merge question","scenario":"Your PR is green except one flaky integration test that fails about one run in five, on code you didn't touch. You want the senior on your team to confirm it's safe to merge, but your draft opens with the full history of the test.","task":"Write a Slack message that puts the question in the first sentence.","tips":["Ask the question first: safe to merge past this failure?","One line of evidence that the flake predates your change.","Make it answerable with a yes or no."],"focus":["clarity","concision"],"placeholder":"Is it safe to merge #482 past the flaky checkout test? It fails ~1 in 5 runs on main too —"},
    {"id":"lead-eng-early-03","level":"early","profession":"engineer","title":"The PR that hides its payoff","scenario":"You're opening a PR that adds a composite index to fix the slow orders query — the account page drops from 4s to 300ms in your testing. Your draft description starts with how you profiled the query.","task":"Write a PR description whose first line states the change and the payoff.","tips":["First line: what changed and why it matters, with the numbers.","The profiling story is supporting detail below.","Reviewers triage by the opening line — make it carry the PR."],"focus":["clarity","structure"],"placeholder":"Adds a composite index on orders(user_id, created_at) — account page query drops from ~4s to ~300ms."},
    {"id":"lead-eng-early-04","level":"early","profession":"engineer","title":"The bug report that buries the impact","scenario":"You found that the payment provider's webhook retries are silently dropped when your endpoint times out, so some orders never get marked as paid. Your ticket draft opens with the log excerpt that led you there.","task":"Write the first two sentences of the bug report: impact first, then the cause.","tips":["Sentence one: what breaks for users and how badly.","Sentence two: the mechanism, in one plain clause.","Logs and repro steps belong below the fold."],"focus":["impact","clarity"]},
    {"id":"lead-eng-early-05","level":"early","profession":"engineer","title":"The first post in the incident channel","scenario":"Error rates on the API just tripled after the 2:05 pm deploy and you're the first to notice. You're about to post in the incident channel, but your draft starts with graphs and half-formed guesses.","task":"Write a 1-2 sentence first post that leads with what's happening and what you're doing about it.","tips":["State the symptom, the suspected trigger, and your next action.","Skip speculation about root cause — that comes later.","People joining the channel should be oriented by line one."],"focus":["clarity","impact"],"placeholder":"API 5xx rate tripled since the 2:05 deploy — starting a rollback now, updates here."},
    {"id":"lead-eng-early-06","level":"early","profession":"engineer","title":"The license question that needs a call","scenario":"The charting library you want to upgrade switched to a license you're not sure the company allows. You need your manager's decision before you proceed, but your draft spends a paragraph on why the upgrade is worth doing.","task":"Write a message that leads with the decision you need and by when.","tips":["Sentence one: the decision and the deadline.","One sentence of context: what changed and what's at stake.","Offer a default: 'If I don't hear back, I'll hold off.'"],"focus":["clarity","structure"]},
    {"id":"lead-eng-early-07","level":"early","profession":"engineer","title":"The handoff that hides the pager risk","scenario":"You're handing the on-call pager to a teammate. The disk-usage alert on the logging cluster will probably fire tonight — it's noisy but has to be checked every time. Your draft opens with a pleasant recap of your quiet week.","task":"Write a handoff note that leads with the one thing they must watch.","tips":["First line: the alert that will fire and what to do when it does.","Link the runbook next to it, not three paragraphs down.","The quiet-week recap is optional trailing detail."],"focus":["precision","structure"],"placeholder":"Watch disk-usage alerts on the logging cluster — likely to fire tonight; check and clear per the runbook:"},
    {"id":"lead-eng-early-08","level":"early","profession":"engineer","title":"The 'is it live?' reply","scenario":"The product manager pings you: \"Is the search fix live for customers yet?\" It shipped an hour ago behind a flag at 50%. Your draft explains feature-flag mechanics before getting to the answer.","task":"Write a reply that answers first, with the caveat in the same breath.","tips":["Answer in the first two words: yes or partly.","The flag percentage is the caveat, not the headline.","Give the date it reaches everyone."],"focus":["concision","clarity"],"placeholder":"Yes — live for 50% of users now, 100% by tomorrow morning."},
    {"id":"lead-eng-early-09","level":"early","profession":"engineer","title":"The review that leads with nits","scenario":"Reviewing a teammate's PR you found one real problem — the new endpoint skips the auth check — plus a handful of style nits. Your draft comment lists everything in file order, so the blocker appears fourth.","task":"Write the top-level review comment so the blocking issue comes first.","tips":["Open with the blocker and label it as the reason for changes.","Group the nits under a clearly optional heading.","Don't let file order decide your emphasis."],"focus":["structure","impact"]},
    {"id":"lead-eng-early-10","level":"early","profession":"engineer","title":"The estimate they asked for","scenario":"Your manager asks how long the CSV import feature will take. Your honest answer is about four days, resting on two assumptions. Your draft opens with everything you don't know yet.","task":"Write a reply that gives the number first, then the two assumptions.","tips":["Lead with the estimate — that's the question.","Name the assumptions in one sentence each.","Say what would change the number, briefly."],"focus":["precision","structure"],"placeholder":"About 4 days, assuming the file-size cap holds and we reuse the existing parser."},
    {"id":"lead-eng-early-11","level":"early","profession":"engineer","title":"The demo that starts with the ticket","scenario":"You're demoing the bulk-edit feature at sprint review. Your plan opens with the ticket's history and the refactor you did along the way, before anyone sees what the feature does.","task":"Write the first two sentences of your demo, leading with what users can now do.","tips":["Open with the user-visible result, shown or stated.","The refactor story earns one sentence at most, later.","Assume half the room will only remember your opening."],"focus":["audience","impact"]},
    {"id":"lead-eng-early-12","level":"early","profession":"engineer","title":"The design-doc comment that buries the concern","scenario":"A senior engineer shared a design doc for the notification service. Your one significant concern is that the fan-out approach won't handle the largest accounts. Your draft buries it under praise and three small questions.","task":"Write feedback that names the main concern in sentence one.","tips":["Lead with the concern and where it bites: largest accounts.","Keep the praise — one sentence, after the point.","Separate the must-discuss from the nice-to-know."],"focus":["clarity","impact"]},
    {"id":"lead-eng-early-13","level":"early","profession":"engineer","title":"The stale-review nudge","scenario":"Your PR has been waiting three days, and the export work you're picking up next depends on it. Your draft follow-up opens with \"sorry to bother you again, no rush at all.\"","task":"Write a follow-up that leads with the ask and a concrete deadline.","tips":["Name the ask: review #517 today.","Say why the timing matters in one clause.","Cut the apology — a clear ask is not an imposition."],"focus":["clarity","impact"],"placeholder":"Could you review #517 today? It blocks the export work I start tomorrow."},
    {"id":"lead-eng-early-14","level":"early","profession":"engineer","title":"The migration that slipped","scenario":"The schema migration you planned for this sprint needs a maintenance window you can't get until next Tuesday. Your draft to your manager opens with everything you tried to avoid the slip.","task":"Write a 2-3 sentence message that states the new date first.","tips":["Lead with the new date and what moves with it.","One sentence on why — the window, not the saga.","Close with what you're doing in the meantime."],"focus":["clarity","impact"]},
    {"id":"lead-eng-early-15","level":"early","profession":"engineer","title":"The quarantine request","scenario":"One integration test has failed 6 of the last 20 CI runs across unrelated PRs, and it's blocking merges for the whole team. You want it quarantined while you investigate. Your draft starts with a list of CI links.","task":"Write a message to the team channel that leads with the request.","tips":["Sentence one: quarantine this test, here's why in a clause.","The failure rate is your one number — use it early.","Say who's investigating and by when."],"focus":["clarity","precision"],"placeholder":"Proposing we quarantine checkout_flow_test — it failed 6 of the last 20 CI runs on unrelated PRs."},
    {"id":"lead-eng-early-16","level":"early","profession":"engineer","title":"The access request","scenario":"You need read access to production logs to debug a customer-reported issue, and only the infra team can grant it. Your draft describes the bug in detail before mentioning what you actually need from them.","task":"Write a request that puts what you need, and why, in the first line.","tips":["Lead with the ask: read access to prod logs, for this ticket.","Infra needs the justification, not the debugging story.","Include the duration if access can be time-boxed."],"focus":["clarity","concision"]},
    {"id":"lead-eng-early-17","level":"early","profession":"engineer","title":"The release note that opens with internals","scenario":"Your fix means exports no longer time out on large workspaces. The draft release note opens with the queue re-architecture that made it possible.","task":"Write the release-note opening line, leading with the user benefit.","tips":["First line: what now works for the user.","Implementation detail is for the curious, below.","Write it in the user's vocabulary, not yours."],"focus":["audience","impact"],"placeholder":"Exports now complete reliably on large workspaces."},
    {"id":"lead-eng-early-18","level":"early","profession":"engineer","title":"The retro point with a long runway","scenario":"In the sprint retro you want to raise that tickets kept changing scope after work started — it happened three times and cost the team days. Your draft starts with the longest of the three stories.","task":"Write a retro comment that names the pattern first, then one example.","tips":["State the pattern in one sentence: scope changed mid-work, three times.","Use your strongest example as evidence, briefly.","End with what you want the team to try."],"focus":["structure","clarity"]},
    {"id":"lead-eng-early-19","level":"early","profession":"engineer","title":"The cross-team question","scenario":"You need to know the rate limit on the internal payments API before you can finish your batch job. Your draft to their channel explains your whole job design before the question appears.","task":"Write a message that leads with the question.","tips":["Question first: what's the rate limit for batch callers?","One sentence of context so they can answer safely.","A clear question gets answered between meetings; an essay waits."],"focus":["concision","clarity"],"placeholder":"What's the rate limit on the internal payments API for batch calls? Context: I'm building a nightly job that —"},
    {"id":"lead-eng-early-20","level":"early","profession":"engineer","title":"The investigation, conclusion first","scenario":"An afternoon of profiling shows the slow dashboard is caused by one N+1 query on team members. Your draft message to the channel replays your entire investigation timeline before the finding.","task":"Write a message that leads with the conclusion, then the key evidence.","tips":["Sentence one: the cause, named plainly.","Pick the two strongest pieces of evidence; drop the rest.","Say what you propose to do about it."],"focus":["clarity","structure"],"placeholder":"The dashboard slowness is one N+1 query on team members — 40 extra queries per page load."},
    {"id":"lead-eng-early-21","level":"early","profession":"engineer","title":"The meeting ask that dances","scenario":"You want 20 minutes with your manager to ask for the upcoming search-migration project — you see it as your growth opportunity this quarter. Your draft says \"maybe we could find some time to chat about a few things sometime.\"","task":"Write a meeting request that states the purpose and duration up front.","tips":["Name the topic and the time: 20 minutes, about the migration project.","Vague requests get deprioritized; specific ones get scheduled.","One sentence on why now."],"focus":["clarity","precision"]},
    {"id":"lead-eng-early-22","level":"early","profession":"engineer","title":"The recommendation after the research","scenario":"A teammate asked which HTTP client the service should standardize on. You compared three options over two days and have a clear pick. Your draft reply walks through the full comparison before naming it.","task":"Write a reply that gives your recommendation in sentence one, reasons after.","tips":["Your pick goes first — that's what they asked for.","Give the top two reasons, not all seven.","Note the runner-up and when it would win instead."],"focus":["structure","clarity"]},
    {"id":"lead-eng-early-23","level":"early","profession":"engineer","title":"The 'I broke staging' message","scenario":"Your migration script wiped the seed data in staging, and QA's testing is paused because of it. You've started a restore that will take about 30 minutes. Your draft explains how the script went wrong before saying any of that.","task":"Write a message that leads with the status and the recovery time.","tips":["Line one: what's broken, that it was you, and when it's back.","People need the ETA before the explanation.","Owning it plainly reads as competence, not failure."],"focus":["clarity","impact"],"placeholder":"Staging seed data is wiped — my migration script. Restore is running; back in ~30 min. QA, please hold until then."},
    {"id":"lead-eng-early-24","level":"early","profession":"engineer","title":"The pairing request in a wall of text","scenario":"You're stuck on a race condition in the websocket reconnect logic and want 45 minutes with the senior engineer tomorrow morning. Your draft is a wall of context about everything you've ruled out.","task":"Write a Slack message that leads with the ask, then the minimum context.","tips":["Ask first: 45 minutes tomorrow morning, pairing on a race condition.","Two sentences of context, maximum.","Offer two time slots to make yes easy."],"focus":["clarity","concision"]},
    {"id":"lead-eng-early-25","level":"early","profession":"engineer","title":"The Friday summary that leads with meetings","scenario":"This week you shipped the rate-limit middleware and two bug fixes, and also sat through incident review and two interview panels. Your Friday note to your manager currently opens with the meetings.","task":"Write the opening line of the summary, leading with what shipped.","tips":["Outcomes first, activity later or not at all.","One crisp headline sentence, then short bullets.","If a meeting mattered, say what came out of it, not that it happened."],"focus":["concision","structure"],"placeholder":"Shipped this week: rate-limit middleware plus the two checkout bug fixes."}
  ],
  "start-with-the-audience": [
    {"id":"audience-eng-early-01","level":"early","profession":"engineer","title":"The outage explained to support","scenario":"Checkout was failing for about 20 minutes and the support team is fielding angry tickets. The real cause: a bad config push made the payment service reject valid card tokens. Support needs something they can tell customers now.","task":"Write a 2-3 sentence explanation the support team can understand and partly reuse with customers.","tips":["Name the symptom and the time window, not the config internals.","Give them one customer-safe sentence they can paste.","Say clearly whether affected customers need to retry or do nothing."],"focus":["audience","clarity"],"placeholder":"Between 2:10 and 2:30 pm some checkouts failed. It's fixed —"},
    {"id":"audience-eng-early-02","level":"early","profession":"engineer","title":"The refactor update your PM can use","scenario":"Your PM asks how the checkout refactor is going. Your honest answer is \"the payment adapter is extracted and the tests are ported, but the retry logic is still coupled to the old queue.\" None of that tells them what they need for the roadmap.","task":"Rewrite the update in 2-3 sentences around what the PM actually cares about: timeline and risk.","tips":["Translate modules-and-tests into on-track or at-risk.","Give the date the feature work can resume.","Keep one technical clause only if it changes their planning."],"focus":["audience","clarity"]},
    {"id":"audience-eng-early-03","level":"early","profession":"engineer","title":"The API handoff to design","scenario":"You finished the profile API that design will build the new settings screen against. Your instinct is to send the endpoint spec and response fields. The designers care about what the screen can show and when.","task":"Write a 3-4 sentence handoff note framed around what design can now build.","tips":["Lead with the capability: what the screen can display and edit.","Translate field names into user-visible data.","Flag the one thing that isn't ready yet and its date."],"focus":["audience","structure"]},
    {"id":"audience-eng-early-04","level":"early","profession":"engineer","title":"The deploy guide for the new teammate","scenario":"A teammate who joined Monday asks how deploys work. Your first draft says \"merge to main, wait for the pipeline, then promote in Spinnaker unless the freeze calendar says otherwise\" — three pieces of shorthand they can't unpack yet.","task":"Rewrite the explanation in 3-4 sentences that assume no team context.","tips":["Spell out every internal name the first time you use it.","Order the steps as they'll experience them.","Point to where they can watch a deploy happen."],"focus":["audience","clarity"]},
    {"id":"audience-eng-early-05","level":"early","profession":"engineer","title":"The release note for QA's eyes","scenario":"You're handing this week's release to QA. Your draft lists merged PRs by title. QA needs to know what changed in user-facing behavior and where regressions are most likely.","task":"Write a 3-4 sentence note telling QA what changed and where to focus testing.","tips":["Frame changes as user-visible behavior, not PR titles.","Name the riskiest area and why it's risky.","Include what did NOT change, so they can skip it."],"focus":["audience","precision"]},
    {"id":"audience-eng-early-06","level":"early","profession":"engineer","title":"The flaky CI cost, in manager terms","scenario":"You want your manager to let you spend two days fixing CI flakiness. Your draft explains test retry mechanics. Your manager thinks in team time and delivery risk.","task":"Write a 2-3 sentence case in terms of what the flakiness costs the team.","tips":["Convert the flake to hours lost or merges delayed per week.","Say what two days buys: a number, not 'better CI'.","Skip the retry internals entirely."],"focus":["audience","impact"],"placeholder":"CI flakes are costing us roughly 4 dev-hours a week in reruns and delayed merges."},
    {"id":"audience-eng-early-07","level":"early","profession":"engineer","title":"The logout bug for customer success","scenario":"A customer-success teammate asks why a big customer keeps getting logged out. The cause: their SSO session tokens expire hourly and the refresh call fails behind their corporate proxy. CS needs to explain it to a frustrated admin.","task":"Write a 2-3 sentence explanation CS can relay, in the customer's terms.","tips":["Describe it from the user's seat: what they see and when.","Name whose side the fix is on without assigning blame.","Give CS the workaround and the fix ETA."],"focus":["audience","clarity"]},
    {"id":"audience-eng-early-08","level":"early","profession":"engineer","title":"One message, two audiences","scenario":"You're announcing the v1 API deprecation in a channel read by both engineers on other teams and their PMs. Engineers need endpoints and dates; PMs need whether their roadmap is affected. Your draft mixes both in every sentence.","task":"Rewrite the announcement to serve one primary audience first, with a labeled section for the other.","tips":["Pick the primary reader — probably the engineers who must act.","Open with what they must do and by when.","Give PMs one clearly labeled takeaway line."],"focus":["audience","structure"]},
    {"id":"audience-eng-early-09","level":"early","profession":"engineer","title":"The security patch announcement","scenario":"You patched a dependency vulnerability and every service owner needs to bump the version by Friday. Your draft opens with the CVE number and CVSS score. Most readers just need to know what to run and when.","task":"Write a 2-3 sentence channel post that leads with the action, sized to the reader.","tips":["Lead with the action: bump package X to version Y by Friday.","One clause on why it matters — severity, in plain words.","Link the CVE for the few who want depth."],"focus":["audience","clarity"],"placeholder":"Action needed by Friday: bump lodash to 4.17.21 in any service you own."},
    {"id":"audience-eng-early-10","level":"early","profession":"engineer","title":"The endpoint described for the docs writer","scenario":"The docs writer asked you to describe the new export endpoint for the public API docs. Your draft is your internal design summary: queue-backed, idempotent, cursor-paginated. External developers need what it does and how to call it.","task":"Write a 3-4 sentence description aimed at an external developer reading the docs.","tips":["Start with what a caller gets: their workspace data as CSV.","Translate 'queue-backed' into what they experience: async, poll for status.","Mention limits they'll actually hit — size, rate."],"focus":["audience","precision"]},
    {"id":"audience-eng-early-11","level":"early","profession":"engineer","title":"The framework upgrade, in roadmap terms","scenario":"You need the PM to accept a sprint of Node 18-to-22 upgrade work. Your draft lists deprecated APIs and breaking changes. The PM cares about why now, what it risks, and what it costs in feature time.","task":"Write a 2-3 sentence case in the PM's terms.","tips":["Lead with the forcing event: end of security support, with the date.","Cost: one sprint. Risk of waiting: name one concrete failure.","Skip the API-by-API detail."],"focus":["audience","impact"]},
    {"id":"audience-eng-early-12","level":"early","profession":"engineer","title":"The altitude check: manager asks about the migration","scenario":"Your manager asks \"how's the data migration going?\" in a hallway conversation. You're deep in it and your instinct is to start at the table you migrated this morning. They want the shape: on track or not, done when, any risk.","task":"Write the 2-sentence answer at the right altitude.","tips":["Answer at project level: percent done, date, biggest risk.","No table names unless one threatens the date.","Offer detail rather than defaulting to it: 'happy to go deeper.'"],"focus":["audience","concision"],"placeholder":"About 70% done, on track for the 15th."},
    {"id":"audience-eng-early-13","level":"early","profession":"engineer","title":"The altitude check: senior wants the detail","scenario":"A senior engineer reviewing your incident follow-up asks exactly how the connection pool got exhausted. Your instinct is to open with a general recap of the incident they already know.","task":"Write a 3-4 sentence answer that goes straight to the mechanism at full technical depth.","tips":["Skip the recap — they were there.","Lead with the mechanism: what held connections and why they weren't released.","Precise names and numbers are the courtesy at this altitude."],"focus":["audience","precision"]},
    {"id":"audience-eng-early-14","level":"early","profession":"engineer","title":"The PR for an outside reviewer","scenario":"Your reviewer this week is from the platform team and has never seen your codebase. Your draft PR description assumes knowledge of your service's job scheduler and its 'shadow mode.' They can't review what they can't place.","task":"Rewrite the PR description's first three sentences so an outsider can review it.","tips":["One sentence of system context before the change.","Define 'shadow mode' in a clause the first time it appears.","Tell them where the risky part of the diff is."],"focus":["audience","structure"]},
    {"id":"audience-eng-early-15","level":"early","profession":"engineer","title":"Reliability work, translated","scenario":"You want the team's PM to hold a sprint for reliability fixes after three noisy weeks. Your draft argues from error budgets and SLO burn. The PM plans in features, customer complaints, and dates.","task":"Write a 2-3 sentence argument translated into the PM's stakes.","tips":["Lead with what customers felt: incidents, minutes down, tickets.","Frame the sprint as protecting the next two launches.","Keep 'SLO' out of it or define it in five words."],"focus":["audience","impact"]},
    {"id":"audience-eng-early-16","level":"early","profession":"engineer","title":"The backend change, explained to mobile","scenario":"Your API change adds a required field to the order-creation call. The mobile team needs to know what breaks for old app versions and what to ship. Your draft describes your validation layer instead.","task":"Write a 3-sentence note to the mobile channel framed around what it means for their app.","tips":["Lead with their consequence: old versions get a 400 after March 1.","Tell them exactly what to send and from which app version.","Offer a compatibility window if one exists — that's their first question."],"focus":["audience","precision"]},
    {"id":"audience-eng-early-17","level":"early","profession":"engineer","title":"The company-wide incident line","scenario":"The incident is resolved and someone needs to post one line in the company-wide channel. Your draft says \"rolled back the regression in the token refresh path in auth-service.\" Most of the company doesn't know what any of that is.","task":"Write the one-sentence company-wide update in plain language.","tips":["Say what users experienced and that it's fixed.","Time window and current status — nothing else.","Save the mechanism for the engineering channel."],"focus":["audience","concision"],"placeholder":"Sign-in was failing for some users from 3:10 to 3:45 pm — it's fixed, and we're writing up the cause."},
    {"id":"audience-eng-early-18","level":"early","profession":"engineer","title":"The webhook explainer for the solutions engineer","scenario":"A solutions engineer setting up a big customer asks how webhook signature verification works so they can guide the customer's developer. Your draft is a paragraph on HMAC internals. They need setup steps and what failure looks like.","task":"Write a 3-4 sentence explanation pitched at what the SE has to do with it.","tips":["Frame it as steps: where the secret lives, what the customer's dev checks.","Describe the failure symptom they'd see if it's wrong.","HMAC is one word of background, not the content."],"focus":["audience","clarity"]},
    {"id":"audience-eng-early-19","level":"early","profession":"engineer","title":"The double-counted events, for the analyst","scenario":"A retry bug double-counted signup events for three days last week, and the data analyst is about to present funnel numbers. Your draft explains the retry logic. The analyst needs which dates, which events, and what to do with them.","task":"Write a 2-3 sentence note giving the analyst exactly what their work needs.","tips":["Lead with the affected range and event type.","Tell them the correction: divide, exclude, or wait for backfill.","The retry mechanics are one optional clause."],"focus":["audience","precision"],"placeholder":"Signup events from May 3-5 are double-counted —"},
    {"id":"audience-eng-early-20","level":"early","profession":"engineer","title":"Explaining rebase to the intern","scenario":"The intern you're buddying asks why their PR says it has conflicts. The fix is to rebase onto main, but they've never rebased and your draft answer is a string of git jargon: 'just rebase onto origin/main and force-push your branch.'","task":"Write a 3-4 sentence explanation with commands, assuming this is their first rebase.","tips":["Say what the problem is in plain terms before the fix.","Give the exact commands in order, with one line on what each does.","Warn about the one scary-looking step (force-push) so it doesn't surprise them."],"focus":["audience","clarity"]},
    {"id":"audience-eng-early-21","level":"early","profession":"engineer","title":"The caching change support should hear about","scenario":"Your caching change means dashboard numbers can now be up to five minutes stale. Support will get 'the numbers are wrong' tickets. Your draft explains cache invalidation strategy; support needs what customers will notice and the standard reply.","task":"Write a 2-3 sentence heads-up for the support channel.","tips":["Describe the symptom in the customer's words: numbers lag a few minutes.","Say it's expected, not a bug, and why it's a good trade.","Give them the one-line reply to use in tickets."],"focus":["audience","clarity"]},
    {"id":"audience-eng-early-22","level":"early","profession":"engineer","title":"The message full of codenames","scenario":"You're asking the data platform team to bump your pipeline's priority. Your draft is written in your team's private vocabulary: \"Falcon backfill is starved because the v2 path preempts it.\" They don't know Falcon or your v2.","task":"Rewrite the request so a stranger to your team can act on it.","tips":["Replace each codename with what the thing actually is.","Their handle on it is the job ID and the queue, not your project name.","State the ask in their system's terms."],"focus":["audience","clarity"]},
    {"id":"audience-eng-early-23","level":"early","profession":"engineer","title":"Why the small ticket is big","scenario":"Your manager assumes the 'add a field to the form' ticket is an afternoon. It touches a shared validation library used by six services. Your draft defends the estimate with library internals; the manager needs the schedule impact and the choice.","task":"Write a 2-3 sentence explanation in schedule terms, ending with the decision you need.","tips":["Lead with the real size: three days, not an afternoon, because six services share the code.","Offer the cheap alternative and what it trades away.","Let them choose with one sentence of technical why."],"focus":["audience","impact"]},
    {"id":"audience-eng-early-24","level":"early","profession":"engineer","title":"The mixed-room demo opening","scenario":"Your sprint demo audience is engineers, the PM, and a designer. You can't serve all three at once. The feature: saved filters on the reports page, which also cut a common support complaint.","task":"Write your opening two sentences, choosing one primary audience deliberately.","tips":["Pick the primary listener and open in their stake.","One sentence can nod to the others — after the opening.","Trying to open for everyone opens for no one."],"focus":["audience","impact"]},
    {"id":"audience-eng-early-25","level":"early","profession":"engineer","title":"The runbook step a stranger can follow at 2am","scenario":"Your runbook step reads: \"If the consumer lags, bounce it the usual way and check the offsets look sane.\" The next person paged might be new, half-asleep, and alone. Nothing in that sentence is executable.","task":"Rewrite the step so someone with no context can execute it, in 3-4 lines.","tips":["Replace 'the usual way' with the exact command.","Define 'sane' with a number or a comparison.","Write for the reader at their worst: 2am, first rotation."],"focus":["audience","precision"],"placeholder":"If consumer lag exceeds 10k messages: restart the consumer with"}
  ],
  "structure-that-carries": [
    {"id":"structure-eng-early-01","level":"early","profession":"engineer","title":"The three-bucket bug triage","scenario":"You're reporting on the twelve bugs that came in from last night's release. Your draft is a flat list in the order they arrived, and nobody reading it can tell what to worry about.","task":"Reorganize the twelve into at most three labeled buckets so the reader sees the shape at a glance.","tips":["Pick buckets by what the reader will do: fix now, fix this sprint, won't fix.","Lead each bucket with a one-line label and a count.","Order the buckets by urgency, not by arrival time."],"focus":["structure","clarity"],"placeholder":"Twelve bugs, three buckets: 2 fix-now (checkout), 7 this-sprint, 3 won't-fix."},
    {"id":"structure-eng-early-02","level":"early","profession":"engineer","title":"The PR description with one governing idea","scenario":"Your PR does three things: extracts the email sender, adds retries, and fixes a typo in a log line. Your draft lists the file changes with no throughline, so the reviewer can't tell what the PR is really about.","task":"Write a description with one governing sentence, then the changes grouped under it.","tips":["State the one thing this PR accomplishes in the first line.","Group the changes as supporting the main goal vs. incidental cleanup.","If the typo fix doesn't fit the theme, say so and move on."],"focus":["structure","clarity"]},
    {"id":"structure-eng-early-03","level":"early","profession":"engineer","title":"The SCQA bug report","scenario":"You're writing up why the nightly report job has been failing. You have all the facts but they're in a jumble. The reader needs the situation, the complication, the question, and your answer in that order.","task":"Write the bug report as four short movements: situation, complication, question, answer.","tips":["Situation: what normally happens and worked before.","Complication: what changed or broke.","Question then answer: what we must decide, and your proposed fix."],"focus":["structure","clarity"]},
    {"id":"structure-eng-early-04","level":"early","profession":"engineer","title":"The PREP answer in standup","scenario":"In standup someone asks whether you'll hit the Friday deadline. You tend to ramble through everything on your plate. PREP — point, reason, example, point — would give it a spine.","task":"Answer the deadline question in four sentences following point, reason, example, point.","tips":["Point: yes or no, up front.","Reason: the single biggest factor.","Example: one concrete piece of evidence, then restate the point."],"focus":["structure","concision"],"placeholder":"Yes, I'll hit Friday. The hard part — the parser — is done and tested."},
    {"id":"structure-eng-early-05","level":"early","profession":"engineer","title":"The design comparison that needs a spine","scenario":"You're comparing two approaches for the export feature — synchronous vs. queued — in a design-doc comment. Your draft alternates points chaotically, so no one can hold the comparison in their head.","task":"Structure the comparison so each option is judged on the same two or three criteria in the same order.","tips":["Pick the criteria that decide it: latency, complexity, cost.","Judge both options on each criterion, in the same order.","End with which one wins and on which criterion."],"focus":["structure","precision"]},
    {"id":"structure-eng-early-06","level":"early","profession":"engineer","title":"The incident timeline that carries","scenario":"You're writing the timeline section of an incident review. Your notes are a pile of timestamps and half-sentences. The reader needs to follow detection, diagnosis, and recovery as three clear phases.","task":"Group the raw events into three labeled phases with the key timestamps in each.","tips":["Phases, not a flat log: detection, diagnosis, recovery.","Keep only the timestamps that mark a phase change or a decision.","One line per phase before the detail."],"focus":["structure","precision"]},
    {"id":"structure-eng-early-07","level":"early","profession":"engineer","title":"The messy TODO list for handoff","scenario":"You're going on vacation and dumping your open work into a handoff doc. Your draft is fifteen unordered TODOs. Whoever covers you needs to see what's urgent, what's blocked, and what can wait.","task":"Reorganize the fifteen items into three groups a covering engineer can act on.","tips":["Group by state: needs action now, blocked on someone, safe to ignore.","Put the one thing that could page them at the very top.","Name the blocker and who owns it for each blocked item."],"focus":["structure","clarity"]},
    {"id":"structure-eng-early-08","level":"early","profession":"engineer","title":"The Slack thread that needs a summary","scenario":"A design discussion in Slack ran to forty messages and reached a decision, but a newcomer can't find it. You're asked to summarize. Your draft just quotes the last few messages.","task":"Write a 3-4 line summary with the decision, the reason, and the one open question.","tips":["Lead with the decision, stated once and plainly.","Give the reason it won over the alternative.","Separate what's settled from the one thing still open."],"focus":["structure","concision"],"placeholder":"Decision: we'll use the queued export. Reason: keeps the request fast for large workspaces."},
    {"id":"structure-eng-early-09","level":"early","profession":"engineer","title":"The estimate broken into parts","scenario":"Your manager wants to know why the search feature is two weeks, not two days. Your draft is a run-on paragraph. A breakdown into phases with rough sizes would make the number defensible.","task":"Structure the estimate as three or four named phases, each with a rough size.","tips":["Break the work into phases the reader recognizes: indexing, query, UI.","Attach a rough size to each so the total adds up visibly.","Flag which phase carries the most uncertainty."],"focus":["structure","precision"]},
    {"id":"structure-eng-early-10","level":"early","profession":"engineer","title":"The release notes grouped by audience impact","scenario":"This release has nine changes: three user-facing, four internal, two bug fixes. Your draft lists them by PR number. Readers can't tell which ones affect them.","task":"Group the nine changes under three headings ordered by who cares most.","tips":["Headings by impact: what users see, what's fixed, what's internal.","Order so the reader's most likely concern is first.","One line per change under its heading — no PR numbers up front."],"focus":["structure","audience"]},
    {"id":"structure-eng-early-11","level":"early","profession":"engineer","title":"The 'why is it slow' answer with a spine","scenario":"A teammate asks in Slack why the dashboard got slow. You have four contributing factors. Dumping all four flat will lose them; you need a governing statement and the factors ranked under it.","task":"Answer with one summary sentence, then the factors ordered by how much they matter.","tips":["Governing line: the dashboard is slow mainly because of one thing.","Rank the factors; put the dominant one first with its share.","Demote the minor factors to a single trailing sentence."],"focus":["structure","precision"]},
    {"id":"structure-eng-early-12","level":"early","profession":"engineer","title":"The onboarding doc that needs sections","scenario":"You're writing the 'first week' doc for new engineers. Your draft is one long scroll of everything you remembered. The reader needs it chunked into stages they'll hit in order.","task":"Impose a structure of three or four dated stages, each with its own short list.","tips":["Order sections by when the newcomer needs them, not by topic.","Day one, first week, first PR — stages they can feel progress against.","Keep each section to what matters at that stage only."],"focus":["structure","audience"]},
    {"id":"structure-eng-early-13","level":"early","profession":"engineer","title":"The retro notes, themed","scenario":"You're capturing the sprint retro. Fourteen comments came up. Your draft transcribes them in speaking order, so the themes are invisible.","task":"Cluster the fourteen comments into three themes, each with a proposed action.","tips":["Find the two or three themes the comments actually cluster into.","Name each theme, then list its comments beneath.","End each theme with one concrete action, not a vibe."],"focus":["structure","clarity"]},
    {"id":"structure-eng-early-14","level":"early","profession":"engineer","title":"The multi-part Slack ask","scenario":"You need three things from the platform team: a config change, a permission grant, and a question answered. Your draft weaves them into one paragraph, so at least one will be missed.","task":"Restructure the message as three numbered, separable asks.","tips":["Number the asks so none gets lost in prose.","Put the most time-sensitive one first.","Make each independently answerable — different people may take different ones."],"focus":["structure","clarity"],"placeholder":"Three asks: (1) bump the timeout to 30s on service-x, (2)"},
    {"id":"structure-eng-early-15","level":"early","profession":"engineer","title":"The pyramid for the migration status","scenario":"Your manager wants a migration status update. You have a governing message (on track, one risk) and a pile of details. Your draft opens with the details and never surfaces the top.","task":"Write the update top-down: governing statement, then the two or three supports.","tips":["Lead with the one-sentence answer: on track, one risk.","Support it with at most three grouped points.","Every detail should ladder up to the opening claim."],"focus":["structure","concision"]},
    {"id":"structure-eng-early-16","level":"early","profession":"engineer","title":"The code-review comment with steps","scenario":"You're asking a teammate to restructure part of their PR. Your draft describes the desired end state in one dense paragraph. They'd act faster on an ordered set of changes.","task":"Rewrite the review comment as an ordered list of concrete changes.","tips":["Turn the paragraph into numbered steps in the order they'd apply them.","Each step is one change, phrased as an action.","Mark which steps are required vs. optional."],"focus":["structure","clarity"]},
    {"id":"structure-eng-early-17","level":"early","profession":"engineer","title":"The demo with three beats","scenario":"You're demoing the new bulk-import feature. Your plan wanders through the UI clicking things. A structure of setup, action, payoff would make it land.","task":"Outline the demo as three beats: the problem, the new flow, the result.","tips":["Beat one: the pain the feature removes, in one sentence.","Beat two: the new flow, shown, narrated in a line each.","Beat three: the payoff — the outcome the user now gets."],"focus":["structure","impact"]},
    {"id":"structure-eng-early-18","level":"early","profession":"engineer","title":"The dependency-risk note","scenario":"You're flagging that three upcoming tickets all depend on the auth refactor landing first. Your draft mentions them scattered through a longer update. The dependency is the point and it's hidden.","task":"Structure a short note that states the dependency first, then what waits on it.","tips":["Lead with the linchpin: the auth refactor gates three tickets.","List what's blocked beneath it, each in a line.","End with the date the linchpin is expected."],"focus":["structure","impact"]},
    {"id":"structure-eng-early-19","level":"early","profession":"engineer","title":"The question with options laid out","scenario":"You're asking your manager to pick a rollout strategy. You have three options with tradeoffs, but your draft mushes them together so no clean choice is visible.","task":"Present the three options in parallel structure so a decision is easy.","tips":["Give each option the same shape: what it is, its main upside, its main cost.","Keep the order and phrasing parallel across all three.","End with your recommendation and one reason."],"focus":["structure","clarity"]},
    {"id":"structure-eng-early-20","level":"early","profession":"engineer","title":"The on-call summary, grouped","scenario":"Your on-call week had eleven pages. Your handoff draft lists all eleven chronologically. The next person needs them grouped so patterns and recurring noise are visible.","task":"Group the eleven pages into categories and note which are recurring.","tips":["Group by cause: same alert repeating, one-offs, real incidents.","Call out the recurring one — it's the actionable signal.","Give counts so the next person knows what's normal."],"focus":["structure","precision"]},
    {"id":"structure-eng-early-21","level":"early","profession":"engineer","title":"The 'what I changed and why' commit body","scenario":"Your commit fixes a subtle timezone bug. Your draft commit body is a stream of consciousness. A reader six months from now needs the what, the why, and the risk cleanly separated.","task":"Write a commit body in three short parts: what changed, why, and what to watch.","tips":["What: the change, in one line.","Why: the bug it fixes, with the trigger condition.","Watch: the edge case a future reader should retest."],"focus":["structure","precision"]},
    {"id":"structure-eng-early-22","level":"early","profession":"engineer","title":"The scattered requirements, ordered","scenario":"A PM sent you feature requirements as a wall of prose mixing must-haves, nice-to-haves, and open questions. You're writing back your understanding. Your draft mirrors their disorder.","task":"Reflect the requirements back in three groups: must-haves, nice-to-haves, open questions.","tips":["Separate what's committed from what's optional from what's unresolved.","Number the open questions so they get answered.","Confirming the structure surfaces disagreements early."],"focus":["structure","clarity"]},
    {"id":"structure-eng-early-23","level":"early","profession":"engineer","title":"The status email with a scannable shape","scenario":"You send a weekly status email that's currently one dense paragraph. Your manager reads it on a phone between meetings. It needs a shape they can scan in ten seconds.","task":"Restructure the update into a headline plus three labeled lines: shipped, in progress, blocked.","tips":["Open with a one-line headline of the week.","Three labels: shipped, in progress, blocked.","One item per label — cut the rest or move it below."],"focus":["structure","concision"],"placeholder":"Headline: rate-limiter shipped, search on track. Shipped:"},
    {"id":"structure-eng-early-24","level":"early","profession":"engineer","title":"The debugging writeup as a story arc","scenario":"You solved a hard intermittent crash and want to write it up so the team learns from it. Your draft jumps between clues randomly. A structure of symptom, hunt, root cause, fix would carry the reader.","task":"Outline the writeup as four labeled sections: symptom, investigation, root cause, fix.","tips":["Symptom first: what users saw and how often.","Investigation: the two or three clues that mattered, not all of them.","Root cause then fix — keep them distinct."],"focus":["structure","clarity"]},
    {"id":"structure-eng-early-25","level":"early","profession":"engineer","title":"The proposal with a single throughline","scenario":"You're proposing the team adopt a shared logging library. Your draft mixes motivation, design, and rollout with no throughline, so it reads as a list of thoughts rather than an argument.","task":"Give the proposal one governing claim and organize everything under three supporting sections.","tips":["Governing claim: one sentence on why this is worth doing now.","Three sections: the problem, the proposed solution, the rollout.","Cut anything that doesn't support the governing claim."],"focus":["structure","impact"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-eng-early-01","level":"early","profession":"engineer","title":"The hedged standup update","scenario":"Your standup update reads: \"So I think I've basically mostly finished the parser, though I still need to sort of double-check a couple of edge cases before I'd say it's really done.\" Under the hedging there's a simple status.","task":"Rewrite it in one clean sentence with no hedges.","tips":["Cut 'I think', 'basically', 'mostly', 'sort of', 'really'.","State what's done and what's left, plainly.","One clause of certainty beats three of qualification."],"focus":["concision","clarity"],"placeholder":"Parser's done; verifying two edge cases before I close it out."},
    {"id":"concise-eng-early-02","level":"early","profession":"engineer","title":"The bloated PR description","scenario":"Your PR description is four paragraphs restating what the diff already shows, with phrases like \"in order to be able to\" and \"due to the fact that.\" A reviewer has to wade through it to find the point.","task":"Cut the description to two tight sentences that say what changed and why.","tips":["'In order to' becomes 'to'; 'due to the fact that' becomes 'because'.","Don't narrate the diff — say what it accomplishes.","If the tests explain it, don't re-explain it in prose."],"focus":["concision","clarity"]},
    {"id":"concise-eng-early-03","level":"early","profession":"engineer","title":"The meta-commentary comment","scenario":"Your code-review comment opens: \"I just wanted to quickly flag something that might possibly be worth thinking about, though it's totally up to you of course.\" The actual point is one sentence, buried.","task":"Rewrite the comment to lead with the point and drop the meta-commentary.","tips":["Cut the throat-clearing about flagging and thinking.","'Might possibly be worth' becomes a direct observation.","You can be polite in five words, not thirty."],"focus":["concision","clarity"]},
    {"id":"concise-eng-early-04","level":"early","profession":"engineer","title":"The nominalized bug report","scenario":"Your bug report says: \"The failure of the retry mechanism results in the non-delivery of notification messages to users.\" Buried in the nouns is a simple action.","task":"Rewrite it with verbs instead of noun-phrases, in one sentence.","tips":["'The failure of the retry mechanism' becomes 'retries fail'.","Turn 'non-delivery of messages' into 'users don't get notified'.","Verbs move; nominalizations sit still."],"focus":["concision","clarity"],"placeholder":"When retries fail, users don't get their notifications."},
    {"id":"concise-eng-early-05","level":"early","profession":"engineer","title":"The redundant-pair Slack message","scenario":"Your message is full of doubled phrases: \"each and every,\" \"first and foremost,\" \"actual and real,\" \"end result.\" It reads padded, and the ask is hard to find.","task":"Cut every redundant pair and tighten the message to its core ask.","tips":["Keep one word from each pair: 'every', 'first', 'real', 'result'.","After cutting pairs, find the single ask and lead with it.","Padding hides the request; stripping it reveals it."],"focus":["concision","clarity"]},
    {"id":"concise-eng-early-06","level":"early","profession":"engineer","title":"The paragraph that should be a sentence","scenario":"You wrote a full paragraph explaining why you missed a deadline, circling the same point three times. Your manager just needs the fact and the new date.","task":"Compress the paragraph to a single sentence.","tips":["Find the one fact and the one date; drop everything else.","Explanations of an explanation can go.","If two sentences say the same thing, keep the shorter."],"focus":["concision","clarity"],"placeholder":"The migration slipped to Tuesday — the maintenance window wasn't free until then."},
    {"id":"concise-eng-early-07","level":"early","profession":"engineer","title":"The filler-heavy incident note","scenario":"Your incident update reads: \"At this point in time, we are currently in the process of investigating the root cause of the issue that is affecting the service.\" That's fourteen words of filler around three of content.","task":"Rewrite it in under ten words with no filler.","tips":["'At this point in time' and 'currently' both mean now — drop both.","'In the process of investigating' is just 'investigating'.","Incident channels reward brevity; nobody rereads padding."],"focus":["concision","clarity"],"placeholder":"Investigating the root cause now; update in 15 minutes."},
    {"id":"concise-eng-early-08","level":"early","profession":"engineer","title":"The over-qualified estimate","scenario":"Your estimate reads: \"It could potentially maybe take somewhere in the range of roughly about three to five days or so, give or take.\" The stacked qualifiers make it useless as a number.","task":"Give the estimate once, with a single honest range.","tips":["One hedge is honest; five is noise — keep at most one.","'Roughly three to five days' says it; the rest is anxiety.","State the assumption that sets the range instead of hedging."],"focus":["concision","precision"],"placeholder":"Three to five days, depending on whether the parser needs rewriting."},
    {"id":"concise-eng-early-09","level":"early","profession":"engineer","title":"The wordy commit message","scenario":"Your commit subject is: \"This commit is a change that makes it so that the timeout value gets increased for the sake of handling slow responses.\" It should be a short imperative line.","task":"Rewrite the commit subject in under ten words, imperative mood.","tips":["Commit subjects start with a verb: 'Increase', not 'This commit'.","Cut 'for the sake of' — say 'to' or drop it.","Fifty characters is the target, not a paragraph."],"focus":["concision","clarity"],"placeholder":"Increase timeout to 30s for slow upstream responses"},
    {"id":"concise-eng-early-10","level":"early","profession":"engineer","title":"The rambling design comment","scenario":"Your design-doc comment runs 200 words to make a single point: the cache should expire on write. You circle it, restate it, and add caveats that don't change the point.","task":"Cut it to under 40 words while keeping the point and one reason.","tips":["Find the sentence that IS the point; delete the runway.","Keep exactly one reason — the strongest.","Caveats that don't change the recommendation can go."],"focus":["concision","clarity"]},
    {"id":"concise-eng-early-11","level":"early","profession":"engineer","title":"The apology that won't end","scenario":"You introduced a regression and your message spends three sentences apologizing before saying what happened or what you're doing. The over-apology delays the useful information.","task":"Rewrite so one brief acknowledgment leads, then the facts and the fix.","tips":["One sentence of ownership is enough; more reads as flailing.","Get to what broke and the ETA fast — that's what people need.","Confidence in the fix reassures more than repeated sorries."],"focus":["concision","impact"]},
    {"id":"concise-eng-early-12","level":"early","profession":"engineer","title":"The over-explained 'no'","scenario":"A teammate asks you to take on a task you don't have bandwidth for. Your reply is a paragraph of soft, winding reasons that never quite says no. It wastes their time and yours.","task":"Write a clear, brief decline in two sentences.","tips":["Say no plainly in the first sentence.","One honest reason — not five.","Offer an alternative or a when, if there is one."],"focus":["concision","clarity"]},
    {"id":"concise-eng-early-13","level":"early","profession":"engineer","title":"The passive, padded status","scenario":"Your status line reads: \"It has been determined by the team that the feature will need to be delayed.\" Passive voice and padding hide who decided and what happens.","task":"Rewrite it active and tight in one sentence.","tips":["Name the actor: 'we're delaying', not 'it has been determined'.","Passive voice adds words and drops responsibility.","Say the new plan, not just that a change occurred."],"focus":["concision","clarity"],"placeholder":"We're delaying the feature to next sprint —"},
    {"id":"concise-eng-early-14","level":"early","profession":"engineer","title":"The bullet list with buried verbs","scenario":"Your handoff bullets each open with 'There is a need to...' or 'It would be good if someone could...' The actions are smothered in preamble.","task":"Rewrite the bullets to start with the action verb.","tips":["Start each bullet with the verb: 'Restart', 'Check', 'Merge'.","Cut 'there is a need to' and 'it would be good if'.","Parallel imperative bullets scan in seconds."],"focus":["concision","structure"]},
    {"id":"concise-eng-early-15","level":"early","profession":"engineer","title":"The 30-second answer that took two minutes","scenario":"In a meeting someone asked if the API change is backward compatible. You talked for two minutes, circling. The answer was yes with one caveat.","task":"Write the spoken answer you should have given in two sentences.","tips":["Lead with yes or no; don't make them wait for it.","One caveat, stated once.","Stop talking when the answer is complete."],"focus":["concision","clarity"],"placeholder":"Yes, backward compatible — except clients on v1.2 need to add one header."},
    {"id":"concise-eng-early-16","level":"early","profession":"engineer","title":"The release note padded with process","scenario":"Your release note reads: \"After extensive testing and review by the team, we are pleased to be able to announce that we have now made improvements to the export functionality.\" The user-facing fact is one clause.","task":"Cut it to the user-facing change in one sentence.","tips":["Users don't care about your testing process — cut it.","'We are pleased to announce' adds nothing.","Say what's better and for whom."],"focus":["concision","audience"],"placeholder":"Exports are faster and no longer time out on large workspaces."},
    {"id":"concise-eng-early-17","level":"early","profession":"engineer","title":"The question wrapped in context","scenario":"You have a yes/no question for a senior, but you front-load three paragraphs of background before asking it. By the time they reach the question they've lost the thread.","task":"Rewrite so the question comes first and the context is one trailing sentence.","tips":["Ask the question in sentence one.","Compress the three paragraphs to the one fact they need to answer.","Everything else is available if they ask — don't front-load it."],"focus":["concision","structure"]},
    {"id":"concise-eng-early-18","level":"early","profession":"engineer","title":"The verbose error message","scenario":"You're writing a user-facing error string and drafted: \"An unexpected error has occurred while attempting to process your request at this time. Please try again later.\" It's long and says nothing actionable.","task":"Rewrite it as one short, specific, actionable line.","tips":["Say what failed and what the user can do about it.","Cut 'unexpected', 'at this time', 'has occurred'.","Specific beats apologetic: name the action to retry."],"focus":["concision","clarity"],"placeholder":"Couldn't save your changes — check your connection and try again."},
    {"id":"concise-eng-early-19","level":"early","profession":"engineer","title":"The doc paragraph to halve","scenario":"A paragraph in your internal doc explains how the rate limiter works, but it's twice as long as it needs to be, with repeated ideas and throat-clearing sentences.","task":"Cut the paragraph in half without losing meaning.","tips":["Delete any sentence that restates the previous one.","Merge two weak sentences into one strong one.","Cut adverbs that don't change the meaning."],"focus":["concision","clarity"]},
    {"id":"concise-eng-early-20","level":"early","profession":"engineer","title":"The 'just circling back' nudge","scenario":"Your follow-up on a stalled review opens with \"Just wanted to circle back and gently follow up on this whenever you get a chance, no pressure at all.\" It's all cushion, no ask.","task":"Rewrite it as a one-line ask with a timeframe.","tips":["Cut the cushioning entirely — it isn't rude to ask.","Name the PR and the day you need it.","A clear ask respects their time more than a soft one."],"focus":["concision","clarity"],"placeholder":"Could you review #517 today? It unblocks tomorrow's work."},
    {"id":"concise-eng-early-21","level":"early","profession":"engineer","title":"The over-detailed standup","scenario":"Your standup runs ninety seconds because you narrate every file you touched. The team needs progress, blockers, and today's plan — three lines.","task":"Compress your standup to three short lines: yesterday, today, blockers.","tips":["Yesterday: the outcome, not the file tour.","Today: the one main thing.","Blockers: name it or say 'none' — don't fill space."],"focus":["concision","structure"],"placeholder":"Yesterday: finished the parser. Today: wiring it into the import flow. Blockers: none."},
    {"id":"concise-eng-early-22","level":"early","profession":"engineer","title":"The tautological log line","scenario":"You wrote a log message: \"Error: an error occurred in the error handler while handling the error.\" It's circular and tells a future debugger nothing.","task":"Rewrite the log line to carry the specific fact a debugger needs.","tips":["Say what operation failed and with what input.","Drop the word 'error' repeating — the log level already says it.","Include the one value that makes it reproducible."],"focus":["concision","precision"],"placeholder":"Failed to parse webhook payload: missing 'event_type' field"},
    {"id":"concise-eng-early-23","level":"early","profession":"engineer","title":"The overqualified recommendation","scenario":"You recommend a library but bury it: \"I might lean slightly toward maybe using X, but honestly I could see arguments either way and it's really not a strong opinion.\" The recommendation disappears.","task":"State the recommendation cleanly, keeping only one honest caveat.","tips":["Say which one you'd pick, without the stack of qualifiers.","One caveat is fine; five erase the recommendation.","If you truly have no preference, say that in one line instead."],"focus":["concision","impact"]},
    {"id":"concise-eng-early-24","level":"early","profession":"engineer","title":"The email that should be three lines","scenario":"You wrote a six-line email to schedule a pairing session, with pleasantries top and bottom. The whole thing is a time proposal that fits in three lines.","task":"Rewrite the email in three lines: the ask, two time options, and a close.","tips":["One line of ask, one of options, one to close.","Cut the weather-talk opener and the effusive sign-off.","Make it answerable with a single word: pick a slot."],"focus":["concision","clarity"]},
    {"id":"concise-eng-early-25","level":"early","profession":"engineer","title":"The dense sentence to break and trim","scenario":"You wrote one 45-word sentence chaining four clauses about why a test is failing. It's technically correct but exhausting, and the reader loses the thread halfway.","task":"Rewrite it as two short sentences, cutting any words that don't carry meaning.","tips":["Break at the natural clause boundary into two sentences.","Cut connective padding: 'which then in turn causes'.","Each sentence should carry one idea, cleanly."],"focus":["concision","clarity"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-eng-early-01","level":"early","profession":"engineer","title":"'The endpoint is slow'","scenario":"You wrote in the channel: \"The search endpoint is really slow lately.\" A senior asks what you mean, because 'slow' could be anything. You have the numbers in your dashboard.","task":"Rewrite the statement with the specific latency, the baseline, and when it changed.","tips":["Replace 'really slow' with a p95 in milliseconds.","Give the baseline it used to be, so the reader can judge.","Say when it started — a date or a deploy."],"focus":["precision","clarity"],"placeholder":"Search p95 jumped from 120ms to 900ms after Tuesday's deploy."},
    {"id":"precision-eng-early-02","level":"early","profession":"engineer","title":"'It affects a lot of users'","scenario":"Your bug report says the crash \"affects a lot of users.\" Your manager needs to prioritize it against other work, and 'a lot' tells them nothing. You have the error-tracker counts.","task":"Restate the impact with a concrete count and rate over a window.","tips":["Give a number: how many users, over what period.","Add a rate — what fraction of sessions hit it.","A skeptic should be able to check your number."],"focus":["precision","impact"],"placeholder":"Roughly 1,400 users hit the crash yesterday — about 3% of active sessions."},
    {"id":"precision-eng-early-03","level":"early","profession":"engineer","title":"From metric to insight","scenario":"You paste a chart into the channel showing memory usage climbing over six hours with the note \"here's the memory graph.\" Nobody knows what you want them to conclude.","task":"Write the one-sentence insight the graph supports, not just a description of it.","tips":["Say what the data means, not what it shows.","'Climbs then never drops' points to a leak — state that.","End with the So What: what it implies for action."],"focus":["precision","impact"],"placeholder":"Memory climbs steadily and never releases — this is a leak, not normal load."},
    {"id":"precision-eng-early-04","level":"early","profession":"engineer","title":"What / So What / Now What","scenario":"You found that 30% of API calls to the pricing service are redundant duplicates. You reported the What but stopped there, so the finding just sits in the channel with no next step.","task":"Write three sentences: the finding, why it matters, and the recommended action.","tips":["What: the fact, with its number.","So What: the cost — latency, spend, load.","Now What: the specific action you propose and who does it."],"focus":["precision","structure"],"placeholder":"30% of pricing-service calls are duplicates. That's wasted latency and load on every checkout. I propose caching the result per request —"},
    {"id":"precision-eng-early-05","level":"early","profession":"engineer","title":"'Should be fine'","scenario":"Asked whether the change is safe to ship Friday, you wrote \"should be fine.\" The reviewer needs to know what that confidence rests on, because 'should' is doing a lot of work.","task":"Replace 'should be fine' with the specific evidence behind your confidence.","tips":["Name what you tested and what passed.","State the one risk that remains, if any, with its likelihood.","Confidence is only useful when its basis is visible."],"focus":["precision","clarity"]},
    {"id":"precision-eng-early-06","level":"early","profession":"engineer","title":"The vague repro steps","scenario":"Your bug ticket says \"sometimes the upload fails if the file is big.\" QA can't reproduce it because nothing there is precise — not 'sometimes', not 'big'.","task":"Rewrite the repro with an exact trigger: size threshold, frequency, conditions.","tips":["Replace 'big' with the size where it starts failing.","Replace 'sometimes' with a frequency or a condition.","Give the exact steps a stranger can follow to see it."],"focus":["precision","clarity"],"placeholder":"Uploads over ~50MB fail about 1 in 3 times on slow connections. Steps:"},
    {"id":"precision-eng-early-07","level":"early","profession":"engineer","title":"The estimate with no basis","scenario":"You told your manager the feature is \"about a week\" but gave nothing to check it against. When it slips, there's no shared understanding of what the week assumed.","task":"Restate the estimate with the two or three assumptions it rests on.","tips":["Keep the number, but attach the assumptions that produce it.","Name what would make it longer.","An estimate with visible assumptions survives contact with reality."],"focus":["precision","structure"]},
    {"id":"precision-eng-early-08","level":"early","profession":"engineer","title":"Passing the skeptic test","scenario":"You claim in a design comment that \"switching to the new serializer will be much faster.\" A skeptical senior will ask: how much, measured how, on what workload. Your draft has none of that.","task":"Rewrite the claim so it survives a skeptic's first three questions.","tips":["Quantify 'much faster' with a measured number.","Say how you measured it and on what input.","Pre-answer the obvious challenge instead of waiting for it."],"focus":["precision","impact"]},
    {"id":"precision-eng-early-09","level":"early","profession":"engineer","title":"'A bunch of errors'","scenario":"Your incident note says the service is throwing \"a bunch of errors.\" The responders need to know which errors, how many, and whether it's growing. 'A bunch' orients no one.","task":"Rewrite it with the error type, the rate, and the trend.","tips":["Name the specific error or status code.","Give a rate per minute, not a vibe.","Say whether it's climbing, flat, or recovering."],"focus":["precision","clarity"],"placeholder":"~200 500s/min from the payment service, up from near zero at 2:05 — still climbing."},
    {"id":"precision-eng-early-10","level":"early","profession":"engineer","title":"The benchmark without a control","scenario":"You report \"the new query runs in 200ms\" as evidence the optimization worked, but you never state what it was before. The number alone proves nothing.","task":"Rewrite the result as a before/after comparison on the same input.","tips":["Always pair the after with the before.","Hold the input constant so the comparison is fair.","State the delta as a factor or percentage, not just two numbers."],"focus":["precision","impact"],"placeholder":"The orders query dropped from 4.1s to 200ms on the same 10k-row workspace — about 20x."},
    {"id":"precision-eng-early-11","level":"early","profession":"engineer","title":"'It's been happening a while'","scenario":"You tell the team a memory issue has been \"happening for a while.\" To decide urgency they need to know since when and whether it's worsening. 'A while' hides both.","task":"Rewrite it with a start date and a trend from the data.","tips":["Anchor it: since which deploy or which day.","Say whether it's stable or accelerating.","Vague duration reads as vague investigation."],"focus":["precision","clarity"]},
    {"id":"precision-eng-early-12","level":"early","profession":"engineer","title":"The data dump with no takeaway","scenario":"You paste twelve rows of per-endpoint latency into the channel and let the reader draw conclusions. Most won't. The one row that matters is lost among the eleven that don't.","task":"Write the one insight the table supports and cut the reader's work to zero.","tips":["Do the reading for them: name the outlier row.","One insight, then the table as backup — not the reverse.","If eleven rows don't matter, don't make them read all twelve first."],"focus":["precision","concision"]},
    {"id":"precision-eng-early-13","level":"early","profession":"engineer","title":"'The tests mostly pass'","scenario":"You report that after your change \"the tests mostly pass.\" A reviewer can't act on 'mostly' — they need to know which fail and whether the failures are yours.","task":"Restate with the exact pass/fail count and the status of each failure.","tips":["Give the count: how many pass, how many fail.","For each failure, say whether it's pre-existing or new.","'Mostly' is where hidden regressions live."],"focus":["precision","clarity"],"placeholder":"312 of 314 pass. The 2 failures are the known flaky checkout tests, not from this change."},
    {"id":"precision-eng-early-14","level":"early","profession":"engineer","title":"The cost claim without units","scenario":"You argue the batch job is \"expensive\" and should be optimized. Your manager needs the cost in comparable terms — dollars or compute-hours — to weigh it against your time.","task":"Rewrite the claim with the cost quantified in a unit that supports a decision.","tips":["Translate 'expensive' into dollars per day or compute-hours.","Compare it to something: the rest of the budget, or your fix time.","Give the payoff of fixing it in the same unit."],"focus":["precision","impact"]},
    {"id":"precision-eng-early-15","level":"early","profession":"engineer","title":"'Users are complaining'","scenario":"You escalate that \"users are complaining about the new layout.\" To act, the PM needs how many, saying what, through which channel. Right now it could be two tweets or two hundred tickets.","task":"Rewrite with the volume, the specific complaint, and the source.","tips":["Give a count and a source: tickets, reviews, or forum posts.","Quote the specific recurring complaint, not 'complaints'.","Distinguish signal from a couple of loud voices."],"focus":["precision","audience"],"placeholder":"37 support tickets since Monday, all about the filters button being hard to find."},
    {"id":"precision-eng-early-16","level":"early","profession":"engineer","title":"The 'it works on my machine' claim","scenario":"You close a bug saying \"can't reproduce, works for me.\" That's not evidence — it doesn't say what environment, version, or data you tried. The reporter will just reopen it.","task":"Rewrite the closing note with the exact conditions you tested under.","tips":["State your version, environment, and the data you used.","Say what you tried that they reported, specifically.","Give them one thing to check that might differ on their side."],"focus":["precision","clarity"]},
    {"id":"precision-eng-early-17","level":"early","profession":"engineer","title":"The rounded-off timeline","scenario":"You say the rollout \"will take a bit\" after enabling the flag. Support wants to tell customers a real window. 'A bit' can't be relayed.","task":"Replace 'a bit' with a concrete rollout schedule and end time.","tips":["Give percentages and times: 25% now, 100% by when.","Name the point at which everyone has it.","Support needs a date they can put in a reply."],"focus":["precision","audience"],"placeholder":"Rolling out now: 25% today, 50% tomorrow, 100% by Thursday morning."},
    {"id":"precision-eng-early-18","level":"early","profession":"engineer","title":"The unquantified risk","scenario":"You warn that the migration \"could cause some downtime.\" Leadership planning a maintenance window needs to know how much and how likely. 'Some' spans a spectrum from seconds to hours.","task":"Rewrite with an estimated duration and a likelihood.","tips":["Give a range for the downtime, in minutes.","Attach a likelihood: expected, possible, worst-case.","Separate the expected case from the worst case explicitly."],"focus":["precision","impact"]},
    {"id":"precision-eng-early-19","level":"early","profession":"engineer","title":"The 'improved performance' PR line","scenario":"Your PR says it \"improves performance.\" The reviewer wants to know which metric moved, by how much, measured how — otherwise the claim is unverifiable and unmergeable on that basis.","task":"Rewrite the line with the metric, the delta, and the measurement method.","tips":["Name the metric that changed, not 'performance'.","Give the before and after, on a stated workload.","Say how you measured so the reviewer can trust it."],"focus":["precision","clarity"],"placeholder":"Cuts p95 render time from 340ms to 90ms on the 500-item list (measured via the profiler over 20 runs)."},
    {"id":"precision-eng-early-20","level":"early","profession":"engineer","title":"The insight hidden in a log paste","scenario":"You paste forty log lines into the incident channel expecting others to spot the problem. They won't read forty lines mid-incident. One line matters.","task":"Quote the single decisive line and state what it tells you.","tips":["Pull out the one line that identifies the cause.","Say in a sentence what it means.","Save the full log for the writeup, not the live channel."],"focus":["precision","concision"]},
    {"id":"precision-eng-early-21","level":"early","profession":"engineer","title":"'Pretty confident it's the cache'","scenario":"You tell the responders you're \"pretty confident it's the cache.\" That confidence needs a basis they can evaluate before acting on it — otherwise you might steer the whole response wrong.","task":"Rewrite with the evidence that points to the cache and one thing that would confirm it.","tips":["Give the observation that implicates the cache.","State what you haven't ruled out yet.","Name the quick check that would confirm or refute it."],"focus":["precision","clarity"]},
    {"id":"precision-eng-early-22","level":"early","profession":"engineer","title":"The vague capacity ask","scenario":"You request \"more memory\" for the service in a ticket to infra. They need a specific number and the reasoning, or the ticket bounces back with questions.","task":"Rewrite the request with the exact amount and the evidence for it.","tips":["Give the number: current limit, requested limit.","Show the usage data that justifies it.","State the headroom you're targeting and why."],"focus":["precision","clarity"],"placeholder":"Requesting the worker's memory limit go from 512MB to 1GB — it OOMs at ~480MB under peak load (graph attached)."},
    {"id":"precision-eng-early-23","level":"early","profession":"engineer","title":"The 'a few edge cases' caveat","scenario":"You note the feature handles \"a few edge cases\" poorly. A reviewer deciding whether to ship needs to know which cases and how bad. 'A few' could be trivial or could be a blocker.","task":"Rewrite naming the specific edge cases and their severity.","tips":["List the actual cases, not the count.","Say what happens in each — error, wrong result, or crash.","Rank them so the reader sees which one might block."],"focus":["precision","clarity"]},
    {"id":"precision-eng-early-24","level":"early","profession":"engineer","title":"The correlation stated as cause","scenario":"You claim \"the errors started because of the deploy\" but your only evidence is that they happened after it. A senior will want you to separate correlation from cause before the team acts.","task":"Rewrite the claim to state what you actually know versus what you're inferring.","tips":["Say the timing evidence plainly: errors began right after the deploy.","Mark the causal claim as a hypothesis, not a fact.","Name the check that would confirm the deploy caused it."],"focus":["precision","clarity"]},
    {"id":"precision-eng-early-25","level":"early","profession":"engineer","title":"The demo claim with no number","scenario":"In your sprint demo you say the new import is \"way faster than before.\" Someone asks how much. You don't have a figure ready, and the claim deflates.","task":"Write the one-sentence demo claim with the concrete speedup baked in.","tips":["Have the number ready: from X to Y, or an N-times factor.","Tie it to something the audience feels: a 5,000-row import.","A measured claim lands; an adjective invites doubt."],"focus":["precision","impact"],"placeholder":"A 5,000-row import that used to take 40 seconds now finishes in under 3."}
  ],
  "executive-presence": [
    {"id":"presence-eng-early-01","level":"early","profession":"engineer","title":"The neutral menu of options","scenario":"Your manager asks which database you should use for the new feature. Your draft lays out three options with pros and cons and stops, leaving the decision entirely to them. You've done the analysis — you have a view.","task":"Rewrite so you recommend one option and defend it, keeping the others as brief alternatives.","tips":["Lead with your pick, not the menu.","Give the one reason it wins for this case.","Mention the runner-up in a clause, not a column."],"focus":["impact","structure"],"placeholder":"I'd use Postgres here — we already run it and the query patterns fit. Considered Mongo but the joins we need make it awkward."},
    {"id":"presence-eng-early-02","level":"early","profession":"engineer","title":"Signposting a review comment","scenario":"Your review comment covers three separate concerns but runs them together, so the author can't tell where one ends and the next begins. A little signposting would make it navigable.","task":"Rewrite the comment with explicit signposts marking the three concerns.","tips":["Number or label the concerns so structure is visible.","Say up front how many there are.","Mark severity: blocker, suggestion, nit."],"focus":["structure","clarity"]},
    {"id":"presence-eng-early-03","level":"early","profession":"engineer","title":"Fact versus judgment in a bug report","scenario":"Your bug report blends what you observed with what you concluded, so the reader can't tell measured fact from your inference. That matters because your inference might be wrong.","task":"Rewrite separating what you observed from what you think it means.","tips":["State the observations first, plainly, as facts.","Then your interpretation, clearly marked as such.","Let the reader agree with the facts even if they doubt the theory."],"focus":["precision","clarity"]},
    {"id":"presence-eng-early-04","level":"early","profession":"engineer","title":"Owning the estimate","scenario":"Asked how long the feature takes, you hedge: \"it kind of depends, hard to say really.\" The team needs a number they can plan around, given with some ownership.","task":"Give a committed estimate you'll stand behind, with the caveat stated once.","tips":["Commit to a number — you can revise it, but give one.","Own it: 'I'll have it by Thursday', not 'it might be done'.","State the single assumption that could move it."],"focus":["impact","precision"],"placeholder":"I'll have it done by Thursday, assuming the API contract doesn't change."},
    {"id":"presence-eng-early-05","level":"early","profession":"engineer","title":"The recommendation in standup","scenario":"In standup you flag that the flaky test is blocking merges but stop short of proposing anything, waiting for someone senior to decide. You actually have a clear view on what to do.","task":"State the problem and your recommended action in two sentences.","tips":["Name the problem, then your proposed fix — don't wait to be asked.","Proposing a course of action is presence, even early in your career.","Make it easy to say yes: one concrete step."],"focus":["impact","clarity"]},
    {"id":"presence-eng-early-06","level":"early","profession":"engineer","title":"The design-doc stance","scenario":"You're commenting on a design doc and you disagree with the proposed caching layer, but your draft only asks tentative questions that dance around the disagreement. A clear stance would serve the doc better.","task":"State your position directly, then support it, in three sentences.","tips":["Say you disagree and with what, plainly.","Give the reason, not a leading question that implies it.","Disagreeing clearly and respectfully is a senior move — do it early."],"focus":["impact","clarity"]},
    {"id":"presence-eng-early-07","level":"early","profession":"engineer","title":"The confident incident update","scenario":"You're giving an update in the incident channel. Your draft is full of 'maybe', 'I guess', 'not sure but' — it undermines confidence in the response even where you do know things. Separate what you know from what you don't.","task":"Rewrite stating what you know firmly and what's still open, without blanket hedging.","tips":["State confirmed facts without hedging them.","Mark the genuinely uncertain parts separately and clearly.","Blanket hedging erodes trust in the parts you're sure of."],"focus":["impact","precision"]},
    {"id":"presence-eng-early-08","level":"early","profession":"engineer","title":"The stand-behind-it review verdict","scenario":"You've reviewed a PR and it's not ready, but your comment softens the verdict so much the author isn't sure whether to merge. Clarity about approve-or-not is a kindness.","task":"Write a top-line verdict that's unambiguous, then the reasons.","tips":["Lead with the verdict: requesting changes, and why in one clause.","Don't approve-with-reservations if you mean don't-merge.","The reasons come after the clear verdict, not instead of it."],"focus":["impact","clarity"]},
    {"id":"presence-eng-early-09","level":"early","profession":"engineer","title":"The recommendation the PM asked for","scenario":"The PM asks whether to ship the feature this week or wait. Your draft lists considerations without landing anywhere. They asked you because you have the technical read — give it.","task":"Give a clear recommendation with the one risk that would change it.","tips":["Recommend ship or wait, in the first sentence.","Give the deciding reason.","Name the one thing that, if true, flips your answer."],"focus":["impact","structure"],"placeholder":"I'd wait until Monday — the retry path isn't covered by tests yet, and that's exactly the risky part."},
    {"id":"presence-eng-early-10","level":"early","profession":"engineer","title":"The 'just my opinion' undercut","scenario":"You end a solid technical argument with \"but that's just my opinion, I could be totally wrong.\" The tag erases the case you just made. There's a way to stay humble without deleting your point.","task":"Rewrite the closing so it stays open to correction without undercutting the argument.","tips":["Drop the self-erasing tag.","Invite challenge on specifics: 'push back if the load numbers are off'.","Humility is inviting scrutiny, not disowning your view."],"focus":["impact","clarity"]},
    {"id":"presence-eng-early-11","level":"early","profession":"engineer","title":"The signposted status update","scenario":"Your weekly update to your manager is one block of prose. A senior would signpost it so the reader knows what's coming and can find what they need. Structure signals command of the material.","task":"Add signposting: a one-line lead, then labeled sections for progress, risk, and asks.","tips":["Open with the headline, then say what sections follow.","Label the sections so the reader can jump.","Put the ask where it won't get lost — its own line."],"focus":["structure","clarity"]},
    {"id":"presence-eng-early-12","level":"early","profession":"engineer","title":"Owning a mistake with composure","scenario":"You pushed a change that broke the build for the team. Your draft either over-apologizes or gets defensive. Presence here is owning it plainly, stating the fix, and moving on.","task":"Write a two-sentence message that owns it, states the fix, and stays composed.","tips":["One clean sentence of ownership — no grovelling.","State what you're doing to fix it and the ETA.","Composure under a mistake reads as senior."],"focus":["impact","clarity"],"placeholder":"I broke the build with my last merge — reverting now, green in a few minutes."},
    {"id":"presence-eng-early-13","level":"early","profession":"engineer","title":"The recommendation buried in analysis","scenario":"You spent a day evaluating whether to fix or rewrite a fragile module. Your writeup is all analysis and no verdict, so the reader has to guess what you'd do. Lead with the call.","task":"Restructure so your recommendation is the first line and the analysis supports it.","tips":["Verdict first: fix or rewrite, in one line.","Then the analysis, framed as why the verdict holds.","End with what you'd need to proceed."],"focus":["impact","structure"]},
    {"id":"presence-eng-early-14","level":"early","profession":"engineer","title":"The meeting where you go quiet","scenario":"In a design review you noticed a real flaw but said nothing, deferring to seniors. Afterwards you draft a message raising it. Presence is raising it in the room, clearly, in the moment.","task":"Write the two-sentence intervention you'd say aloud in the meeting.","tips":["Name the concern plainly and where it bites.","Frame it as a question the group should resolve, not a challenge.","Early-career presence is contributing the observation, confidently."],"focus":["impact","clarity"]},
    {"id":"presence-eng-early-15","level":"early","profession":"engineer","title":"Separating what happened from whose fault","scenario":"Writing an incident note, your draft mixes the sequence of events with implied blame. Presence is stating the facts cleanly and keeping blame out — it makes the note more useful and more trusted.","task":"Rewrite the note stating events neutrally, with no attribution of fault.","tips":["Describe what happened, not who erred.","Passive-blame phrasing like 'someone forgot' has no place here.","Blameless notes get honest information; blame-laden ones don't."],"focus":["clarity","precision"]},
    {"id":"presence-eng-early-16","level":"early","profession":"engineer","title":"The confident 'here's what I'd do'","scenario":"A teammate is stuck and asks for your take on a tricky concurrency bug. Your draft lists possibilities without committing. They want your best judgment, stated with some conviction.","task":"Give your recommended approach in three sentences, owning the call.","tips":["Lead with what you'd try first and why.","Give a fallback if the first doesn't pan out.","Conviction with a fallback is confidence, not arrogance."],"focus":["impact","structure"]},
    {"id":"presence-eng-early-17","level":"early","profession":"engineer","title":"The over-deferential Slack ask","scenario":"You need a senior's input and your draft apologizes three times for taking their time before asking anything. The excessive deference makes you sound unsure you belong. Ask like a colleague.","task":"Rewrite the ask as one confident, respectful message.","tips":["One brief courtesy, then the clear ask.","You're a teammate with a good question, not an intruder.","Respect their time by being crisp, not by apologizing."],"focus":["impact","concision"]},
    {"id":"presence-eng-early-18","level":"early","profession":"engineer","title":"The demo where you own the work","scenario":"You built the feature but your demo intro is all 'we' and passive voice, so it's unclear you did it. You can be a team player and still own your contribution clearly.","task":"Write a demo opening that credits the team while clearly stating what you built.","tips":["Say what you built without hiding behind 'we'.","Crediting collaborators and owning your part aren't in conflict.","Clear ownership helps your manager see your work."],"focus":["impact","clarity"]},
    {"id":"presence-eng-early-19","level":"early","profession":"engineer","title":"The recommendation with a clear default","scenario":"You're asking your manager to approve a small architectural change. Rather than leaving it fully open, presence is proposing a default: what you'll do unless they object.","task":"Write the ask with a stated default action if you don't hear back.","tips":["Recommend the action and say you'll proceed unless told otherwise.","Give a deadline for the objection.","Defaults move work forward without needing a meeting."],"focus":["impact","clarity"],"placeholder":"Planning to split the payments module into two services next sprint — flag by Friday if you'd rather I hold off."},
    {"id":"presence-eng-early-20","level":"early","profession":"engineer","title":"The 'I think maybe possibly' pattern","scenario":"Your messages stack tentative words — 'I think maybe we could possibly' — even when you're sure. It's a verbal tic that undercuts your authority. Strip it where you actually know.","task":"Rewrite a sure statement of yours with the tentative stack removed.","tips":["When you know, say it: 'We should', not 'I think maybe we could'.","Reserve tentative language for genuine uncertainty.","Directness where warranted builds credibility for where it isn't."],"focus":["impact","concision"]},
    {"id":"presence-eng-early-21","level":"early","profession":"engineer","title":"The clear technical stance to a senior","scenario":"A senior proposes an approach you think is over-engineered for the problem. Your draft agrees to avoid friction. Presence is respectfully making the case for the simpler path.","task":"Write a respectful three-sentence pushback proposing the simpler approach.","tips":["Acknowledge their approach, then propose the simpler one.","Give the reason: the complexity isn't earned by this problem.","Disagreeing up the ladder, with evidence, is a growth signal."],"focus":["impact","clarity"]},
    {"id":"presence-eng-early-22","level":"early","profession":"engineer","title":"The verdict-first on-call summary","scenario":"Your on-call handoff buries the one thing that matters — the service is stable but one alert needs watching — under a neutral recap. Lead with the judgment.","task":"Open the handoff with your one-line assessment, then the detail.","tips":["Lead with the state: stable, one thing to watch.","Give your judgment, not just a data recap.","The reader wants your read, not to redo your week."],"focus":["impact","structure"],"placeholder":"Overall stable this week — one thing to watch: the disk-usage alert on logging, likely to fire tonight."},
    {"id":"presence-eng-early-23","level":"early","profession":"engineer","title":"The proposal that asks permission to think","scenario":"You want to propose a refactor but your draft opens by asking whether you're even allowed to suggest it. That framing gives away your standing. Propose it directly.","task":"Rewrite the opening to propose the idea directly, without asking permission to have it.","tips":["Lead with the proposal, not a request to make one.","Frame it as a considered idea with a reason.","You don't need permission to think; you need a good case."],"focus":["impact","clarity"]},
    {"id":"presence-eng-early-24","level":"early","profession":"engineer","title":"Fact and judgment in a status update","scenario":"Your status update mixes 'the migration is 70% done' (fact) with 'so we're basically fine' (judgment) in a way that blurs them. The reader deserves to weigh your judgment separately from the fact.","task":"Rewrite so the measured facts and your assessment are clearly distinct.","tips":["State the fact with its number, unqualified.","Then your assessment, labeled as such.","Let the reader trust the fact and evaluate the judgment on its own."],"focus":["precision","clarity"]},
    {"id":"presence-eng-early-25","level":"early","profession":"engineer","title":"The clear ask, confidently made","scenario":"You want to be assigned the upcoming caching project as a growth opportunity. Your draft hints at interest without asking. Presence is stating the want clearly and why you're ready.","task":"Write a two-sentence message that asks for the project and makes the case.","tips":["Ask directly for the project — hints get overlooked.","Give one reason you're the right person for it.","Confident, specific asks are how early-career engineers grow."],"focus":["impact","clarity"]}
  ],
  "answering-under-pressure": [
    {"id":"pressure-eng-early-01","level":"early","profession":"engineer","title":"'Why isn't it done yet?'","scenario":"In standup your manager asks, a little sharply, why the feature isn't done. Your instinct is to defend yourself with everything that got in the way. What they asked is a simple status question.","task":"Answer the question first — where it stands and when it'll land — before any explanation.","tips":["Answer what was asked: current state and new ETA.","Explanation comes after, kept to one clause.","Defensiveness reads as excuse; a clear status reads as control."],"focus":["clarity","impact"],"placeholder":"It'll be done tomorrow — the API contract changed midweek, which cost a day."},
    {"id":"pressure-eng-early-02","level":"early","profession":"engineer","title":"The 'did you test this?' in review","scenario":"A senior comments on your PR: \"Did you actually test the error path?\" It stings, but the honest answer is you tested the happy path only. Don't get defensive; answer straight.","task":"Answer the question honestly, then say what you'll do about the gap.","tips":["Answer directly: no, not the error path yet.","Don't manufacture a defense — own the gap.","Follow with the concrete next step: adding the test now."],"focus":["clarity","impact"]},
    {"id":"pressure-eng-early-03","level":"early","profession":"engineer","title":"The 'I don't know' with a path","scenario":"In an incident call someone asks you why the queue backed up. You genuinely don't know yet. Saying a confident guess would be worse than an honest 'not yet, but here's how I'll find out.'","task":"Give an honest 'I don't know yet' paired with how and when you'll know.","tips":["Say you don't know yet — plainly, without flailing.","State the specific check you'll run to find out.","Give a time you'll report back."],"focus":["clarity","impact"],"placeholder":"Don't know yet — checking the consumer logs now, I'll have an answer in five minutes."},
    {"id":"pressure-eng-early-04","level":"early","profession":"engineer","title":"The pushback on your estimate","scenario":"Your manager pushes back: \"Two weeks seems too long for this.\" Instead of caving or digging in, answer the challenge with the specifics that justify the number.","task":"Respond with the concrete reason the estimate holds, in two or three sentences.","tips":["Don't cave reflexively and don't get defensive.","Point to the specific work that fills the two weeks.","Offer what you'd cut to hit a shorter number, if they want."],"focus":["clarity","precision"]},
    {"id":"pressure-eng-early-05","level":"early","profession":"engineer","title":"The question you dodged","scenario":"A PM asks a yes/no question — will the feature be ready for the Thursday launch — and your draft answers a different, easier question about progress. Answer the one they asked.","task":"Rewrite to answer the actual yes/no question first, then add context.","tips":["Answer yes or no in the first word.","Resist swapping in the question you'd rather answer.","Context is fine after the answer, not instead of it."],"focus":["clarity","impact"],"placeholder":"No — it won't be ready for Thursday. Realistically Monday."},
    {"id":"pressure-eng-early-06","level":"early","profession":"engineer","title":"The hostile 'this is broken again'","scenario":"A frustrated teammate posts \"the deploy pipeline is broken AGAIN, who keeps doing this.\" You didn't cause it but you can help. Don't match the heat; answer with facts and a next step.","task":"Respond calmly with what you can confirm and the immediate action, in two sentences.","tips":["Don't absorb or return the frustration.","State what you can verify right now.","Move it to action: what you'll check first."],"focus":["clarity","impact"]},
    {"id":"pressure-eng-early-07","level":"early","profession":"engineer","title":"The 'why did you choose that?' challenge","scenario":"In a design review a senior asks why you picked the approach you did, in a tone that sounds skeptical. Answer the actual question — your reasoning — rather than retreating.","task":"Give the reasoning behind your choice in three sentences, without backpedaling.","tips":["Answer the question: the reason you chose it.","Don't abandon the choice at the first sign of doubt.","If their concern is valid, acknowledge it and adjust — on the merits."],"focus":["clarity","structure"]},
    {"id":"pressure-eng-early-08","level":"early","profession":"engineer","title":"The status put on the spot in a meeting","scenario":"In a cross-team sync someone unexpectedly asks you for the status of your piece. You're caught off guard and start rambling through detail. Compose a crisp answer on the spot.","task":"Write the two-sentence answer you'd give: state, ETA, one risk.","tips":["Lead with the one-line state, even under surprise.","Give the ETA and the single biggest risk.","A calm two-sentence answer beats a nervous paragraph."],"focus":["clarity","concision"],"placeholder":"My piece is on track for Friday. One risk: it depends on the auth change landing first."},
    {"id":"pressure-eng-early-09","level":"early","profession":"engineer","title":"The 'can you just make it work?' pressure","scenario":"Under deadline pressure a PM asks you to skip the tests to ship faster. Answering under pressure means neither a flat refusal nor caving — a clear response with the tradeoff.","task":"Respond with the risk of skipping and a concrete faster-but-safe alternative.","tips":["Name the specific risk of skipping tests here.","Offer a middle path: cover the risky path only, ship the rest.","Answer the underlying need — speed — not just the literal ask."],"focus":["impact","clarity"]},
    {"id":"pressure-eng-early-10","level":"early","profession":"engineer","title":"The blame question in the retro","scenario":"In the retro someone asks, pointedly, \"whose change caused the outage?\" It was yours. Answer honestly and steer toward the fix, not the defense.","task":"Own it in one sentence and redirect to what prevents a recurrence.","tips":["Answer the factual question: it was my change.","Don't over-explain or deflect.","Pivot to the systemic fix — that's what the retro is for."],"focus":["clarity","impact"]},
    {"id":"pressure-eng-early-11","level":"early","profession":"engineer","title":"The 'are you sure?' repeated","scenario":"You said the fix is safe, and a senior asks \"are you sure?\" twice. The repetition rattles you. Answer with the basis for your confidence rather than either doubling down blindly or collapsing.","task":"Restate your confidence with the specific evidence behind it, calmly.","tips":["Don't just repeat 'yes' louder — give the evidence.","State exactly what you tested that makes you sure.","If there's a residual risk, name it — that's honest confidence."],"focus":["clarity","precision"]},
    {"id":"pressure-eng-early-12","level":"early","profession":"engineer","title":"The scope question you can't fully answer","scenario":"A stakeholder asks whether your change will affect their team's integration. You know part of the answer but not all. Give what you know and a clear path to the rest — don't guess.","task":"Answer the known part firmly and mark the unknown part with a next step.","tips":["Split it: here's what I'm sure of, here's what I need to check.","Don't paper over the gap with a guess.","Commit to confirming the unknown by a time."],"focus":["clarity","impact"]},
    {"id":"pressure-eng-early-13","level":"early","profession":"engineer","title":"The interruption in your explanation","scenario":"You're explaining a bug's cause and a senior cuts in: \"just tell me if it's fixed.\" You were mid-detail. Read the room and give the headline they want first.","task":"Answer the interrupting question in one line, then offer the detail if wanted.","tips":["Give the headline they asked for immediately.","Drop the detail you were building toward.","Offer depth on request rather than pushing it."],"focus":["clarity","concision"],"placeholder":"Fixed and deployed — happy to walk through the cause if useful."},
    {"id":"pressure-eng-early-14","level":"early","profession":"engineer","title":"The 'this should be simple' minimizing","scenario":"A PM says the task you flagged as complex \"should be simple\" and asks why it isn't. Don't get defensive; answer with the specific reason the complexity is real.","task":"Explain the real source of complexity in two sentences, without sounding defensive.","tips":["Acknowledge it looks simple from outside.","Name the specific thing that makes it not: the shared dependency.","Facts, not frustration, change their mental model."],"focus":["clarity","precision"]},
    {"id":"pressure-eng-early-15","level":"early","profession":"engineer","title":"The public 'why is this taking so long'","scenario":"In a channel visible to other teams, someone asks why your fix is taking so long. The audience raises the stakes. Answer factually and briefly without getting drawn into a defense in public.","task":"Give a brief, factual public answer and offer to take detail offline.","tips":["Keep the public answer short and non-defensive.","State the honest status and next milestone.","Offer to discuss specifics in a thread or DM."],"focus":["clarity","concision"]},
    {"id":"pressure-eng-early-16","level":"early","profession":"engineer","title":"The 'did you consider X?' you didn't","scenario":"A reviewer asks if you considered a concurrency edge case. You didn't. The tempting move is to imply you did. The honest, stronger move is to say no and thank them.","task":"Answer honestly that you hadn't, and say what you'll do now.","tips":["Say no plainly — pretending you did is worse.","Thank them; they caught something real.","State the concrete follow-up you'll take."],"focus":["clarity","impact"],"placeholder":"No, I hadn't — good catch. I'll add a test for the concurrent-write case and handle it before merging."},
    {"id":"pressure-eng-early-17","level":"early","profession":"engineer","title":"The rapid-fire incident questions","scenario":"During an incident, several people ask you things at once: is it users or internal, is it growing, what's the ETA. You feel the pressure to answer all instantly and mangle it.","task":"Answer the three questions in three short, ordered lines.","tips":["Take them one at a time, in a clear order.","One line each — no cross-contamination.","If you don't know one, say so and move on."],"focus":["clarity","structure"]},
    {"id":"pressure-eng-early-18","level":"early","profession":"engineer","title":"The 'just give me a date' demand","scenario":"Your manager, impatient with ranges, says \"just give me a single date.\" You have real uncertainty. Answer with a committed date and the caveat that could move it — not a range disguised as an answer.","task":"Give one committed date plus the single condition that could change it.","tips":["Commit to a date — they asked for one.","Attach exactly one caveat, the load-bearing one.","A date with one honest condition beats a fuzzy range."],"focus":["clarity","precision"],"placeholder":"The 20th. The only thing that moves it is if the vendor API isn't ready by the 15th."},
    {"id":"pressure-eng-early-19","level":"early","profession":"engineer","title":"The challenge to your bug diagnosis","scenario":"You posted a root cause and a senior replies \"I don't think that's right.\" You might be wrong, or they might be. Answer by inviting the specific disagreement rather than defending or folding.","task":"Respond by asking what specifically they'd expect to see if you were wrong.","tips":["Stay curious, not defensive — you want the truth.","Restate your evidence briefly.","Ask what observation would change your mind, or theirs."],"focus":["clarity","precision"]},
    {"id":"pressure-eng-early-20","level":"early","profession":"engineer","title":"The 'why didn't you flag this sooner?'","scenario":"A risk you noticed a week ago just materialized, and your manager asks why you didn't raise it earlier. Answer honestly — you underestimated it — without excuses, and say how you'll flag earlier next time.","task":"Answer honestly in two sentences: what happened, and the change going forward.","tips":["Own the honest reason: you misjudged the likelihood.","Skip the elaborate justification.","State the concrete habit change that prevents a repeat."],"focus":["clarity","impact"]},
    {"id":"pressure-eng-early-21","level":"early","profession":"engineer","title":"The 'can we ship without the migration?'","scenario":"Under pressure to hit a date, a stakeholder asks if you can ship without the risky migration. The real answer is nuanced. Answer the question directly, then give the honest tradeoff.","task":"Answer yes/no first, then the one consequence they need to weigh.","tips":["Give the direct answer before the nuance.","Then the single most important consequence.","Don't hide the answer inside the caveats."],"focus":["clarity","impact"]},
    {"id":"pressure-eng-early-22","level":"early","profession":"engineer","title":"The senior's 'walk me through your logic'","scenario":"A senior, not hostile but exacting, says \"walk me through your logic\" on a decision you made quickly. Under the spotlight you're tempted to over-justify. Give the actual reasoning, cleanly.","task":"Lay out your reasoning in three clear steps, owning any weak link.","tips":["Give the reasoning as steps, not a defense.","If a step was a guess, say so — don't dress it up.","Inviting scrutiny of your logic is how you learn."],"focus":["clarity","structure"]},
    {"id":"pressure-eng-early-23","level":"early","profession":"engineer","title":"The 'is the data safe?' in an incident","scenario":"Mid-incident, someone asks the tense question: \"did we lose any customer data?\" You're not certain yet. This is the worst moment to guess. Answer with honest status and urgency.","task":"Give an honest status on data safety and the immediate check underway.","tips":["Don't reassure beyond what you know — the stakes are too high.","Say exactly what you're checking to confirm.","Give a tight time for a definitive answer."],"focus":["clarity","precision"],"placeholder":"No confirmed data loss so far — verifying the last hour of writes now, definitive answer in 10 minutes."},
    {"id":"pressure-eng-early-24","level":"early","profession":"engineer","title":"The 'you said it would work' callback","scenario":"A feature you were confident about failed in production, and someone reminds you \"you said this would work.\" Don't get defensive about the past claim; answer with what you know now and the fix.","task":"Acknowledge the miss briefly and pivot to the current status and fix.","tips":["Acknowledge it without relitigating your earlier confidence.","Move to now: what's happening and what you're doing.","Composure after being wrong is the skill here."],"focus":["clarity","impact"]},
    {"id":"pressure-eng-early-25","level":"early","profession":"engineer","title":"The question outside your area","scenario":"In a meeting you're asked a networking question that's genuinely outside what you work on. Guessing would mislead. Answer honestly and point to who does know.","task":"Give an honest 'that's outside my area' and route it to the right person or next step.","tips":["Don't fake expertise you don't have.","Say plainly it's not your area.","Redirect: name who'd know, or offer to find out."],"focus":["clarity","impact"],"placeholder":"That's outside what I work on — the platform team owns the networking layer; I can loop them in."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-eng-early-01","level":"early","profession":"engineer","title":"The case for paying down tech debt","scenario":"You want the team to spend a sprint refactoring the tangled orders module. A flat list of code smells won't persuade anyone. A before/after story — what life is like now versus after — will.","task":"Write a 3-4 sentence pitch framed as the change from the painful now to the better after.","tips":["Paint the now: what breaks and how often, concretely.","Paint the after: what becomes easy or safe.","The gap between them is your argument."],"focus":["impact","structure"],"placeholder":"Right now every change to orders takes twice as long and risks the checkout bug. After a sprint of cleanup,"},
    {"id":"narrative-eng-early-02","level":"early","profession":"engineer","title":"Making the stakes concrete","scenario":"You're arguing to fix a slow query, but your case is abstract: \"it's not very efficient.\" To persuade, make the stakes something the reader can feel — a real user waiting, a real cost.","task":"Rewrite the argument so the stakes are concrete and felt, in two or three sentences.","tips":["Turn 'inefficient' into a person waiting four seconds.","Attach a number: how many users, how often.","Concrete stakes move people; abstractions don't."],"focus":["impact","precision"]},
    {"id":"narrative-eng-early-03","level":"early","profession":"engineer","title":"Pre-empting the strongest objection","scenario":"You're proposing to adopt a new testing framework. The strongest objection is the migration cost. Your draft ignores it and just praises the framework, so the objection will sink you in the meeting.","task":"Rewrite the proposal to name and answer the migration-cost objection head on.","tips":["State the objection before someone else does.","Answer it with a real plan: incremental, one module at a time.","Addressing the hard part builds trust in the rest."],"focus":["impact","structure"]},
    {"id":"narrative-eng-early-04","level":"early","profession":"engineer","title":"The 'why this bug matters' framing","scenario":"You want a low-priority-looking bug reprioritized. On its face it's a minor display glitch, but it erodes trust in the numbers on every dashboard. Frame the real stakes, not the surface.","task":"Write a 2-3 sentence case that reframes the bug around what's actually at risk.","tips":["Move from the symptom to what it costs: users doubting all the data.","Tell the small story of a user who stops trusting the dashboard.","Reframing changes the priority more than severity labels do."],"focus":["impact","audience"]},
    {"id":"narrative-eng-early-05","level":"early","profession":"engineer","title":"Selling the boring infrastructure work","scenario":"You want buy-in for upgrading the CI pipeline — unglamorous work no one's excited about. Persuasion here is connecting the dull task to something the team cares about: their own daily pain.","task":"Write a pitch that links the CI work to a pain the team feels every day.","tips":["Anchor it in their lived experience: the 20-minute waits.","Frame the upgrade as buying back their time.","Make the benefit personal to the listeners, not abstract."],"focus":["impact","audience"]},
    {"id":"narrative-eng-early-06","level":"early","profession":"engineer","title":"The before/after in a demo","scenario":"You're demoing a feature that streamlines a clunky workflow. Just showing the new flow won't land the value — the audience needs to feel the old pain first, then the relief.","task":"Structure a two-beat demo narrative: the old painful way, then the new way.","tips":["Show or describe the old flow's friction first.","Then the new flow, so the contrast does the persuading.","The relief only registers against the remembered pain."],"focus":["impact","structure"]},
    {"id":"narrative-eng-early-07","level":"early","profession":"engineer","title":"Persuading a teammate to change approach","scenario":"A teammate is building something the hard way and you see a simpler path. A blunt \"you're doing it wrong\" won't persuade. A story of where their approach leads will.","task":"Write a persuasive 3-sentence message that shows where the current path ends up.","tips":["Acknowledge why their approach is reasonable.","Walk forward to the problem it hits later.","Offer the simpler path as avoiding that future pain."],"focus":["impact","clarity"]},
    {"id":"narrative-eng-early-08","level":"early","profession":"engineer","title":"The proposal that pre-empts 'why now?'","scenario":"You're proposing to add monitoring the team has lived without for a year. The obvious objection is 'why now, we've been fine.' Pre-empt it with what changed and what the next incident costs.","task":"Write a proposal opening that answers 'why now' before it's asked.","tips":["Name what changed that makes this urgent now.","Quantify the risk of the next blind-spot incident.","'We've been lucky' is not 'we've been fine' — make that clear."],"focus":["impact","structure"]},
    {"id":"narrative-eng-early-09","level":"early","profession":"engineer","title":"The stakes for a small audience","scenario":"You're persuading just your manager to let you spend two days on a spike. The stakes that matter to them are their planning risk. Frame the spike as de-risking a decision they have to make.","task":"Write a 2-3 sentence pitch framed around the manager's own risk.","tips":["Frame it as reducing a risk they own.","Two days now versus a two-week wrong turn later.","Speak to their stake, not your curiosity."],"focus":["impact","audience"]},
    {"id":"narrative-eng-early-10","level":"early","profession":"engineer","title":"The retro story that drives change","scenario":"In the retro you want a real process change, not just venting. Turn the incident into a short narrative — how it unfolded and where it could have been caught — that makes the fix obvious.","task":"Write a 3-4 sentence retro narrative that makes the needed change feel inevitable.","tips":["Tell it as a sequence: here's where it started to go wrong.","Mark the point where a small check would have stopped it.","Let the fix emerge from the story, not as a bolt-on."],"focus":["structure","impact"]},
    {"id":"narrative-eng-early-11","level":"early","profession":"engineer","title":"Making an abstract risk vivid","scenario":"You're warning that the single database has no failover — an abstract risk until it isn't. To persuade the team to prioritize it, make the failure scenario concrete and vivid.","task":"Write a short, vivid description of the failure and its consequences.","tips":["Describe the specific bad day: the DB dies, and then what.","Trace the blast radius through to users and the team.","Vividness turns 'someday' into 'we should act'."],"focus":["impact","precision"]},
    {"id":"narrative-eng-early-12","level":"early","profession":"engineer","title":"The 'here's what changes for you' pitch","scenario":"You're proposing a new code-review guideline to the team. People resist process changes. Persuade by leading with what improves in each person's day, not with the rule itself.","task":"Write the pitch leading with the concrete benefit to each teammate.","tips":["Lead with what gets better for the individual reviewer.","The rule is the mechanism, not the headline.","People adopt changes that obviously help them."],"focus":["impact","audience"]},
    {"id":"narrative-eng-early-13","level":"early","profession":"engineer","title":"Pre-empting 'that's not our job'","scenario":"You want your team to own a shared library nobody maintains. The objection is 'that's not our responsibility.' Pre-empt it by showing why the team is already paying the cost of it being ownerless.","task":"Write a 2-3 sentence case that pre-empts the ownership objection.","tips":["Show the team already bears the cost of no owner.","Reframe ownership as reducing that existing pain.","Answer the objection inside the pitch, not after."],"focus":["impact","structure"]},
    {"id":"narrative-eng-early-14","level":"early","profession":"engineer","title":"The change story for a migration","scenario":"You're announcing a migration to a new deploy system and need the team on board. A dry feature comparison won't motivate. A before/after of their deploy experience will.","task":"Write a 3-4 sentence announcement framed as the change to the team's daily experience.","tips":["Before: the current deploy friction they know.","After: what deploying feels like on the new system.","Sell the experience, not the technology."],"focus":["audience","impact"]},
    {"id":"narrative-eng-early-15","level":"early","profession":"engineer","title":"The concrete cost of the flaky test","scenario":"You want the team to prioritize fixing CI flakiness, but 'it's annoying' won't move it up the backlog. Make the cost concrete and cumulative so it's obviously worth a fix.","task":"Write a 2-3 sentence case that makes the recurring cost tangible.","tips":["Add it up: hours lost per week, over a quarter.","Name the second-order cost: people stop trusting red builds.","A tangible running total persuades better than a complaint."],"focus":["impact","precision"],"placeholder":"The flaky checkout test cost us about 5 reruns a day this week — roughly 3 hours across the team, and people are starting to ignore red builds."},
    {"id":"narrative-eng-early-16","level":"early","profession":"engineer","title":"The objection you're tempted to hide","scenario":"Your proposal to rewrite the parser has one real weakness: it'll temporarily slow feature work. You're tempted to leave it out. Naming it yourself is more persuasive than being caught on it.","task":"Rewrite the proposal to surface the weakness and address it honestly.","tips":["State the downside plainly — hiding it costs you trust.","Bound it: how long the slowdown lasts.","Show why the payoff still wins."],"focus":["impact","clarity"]},
    {"id":"narrative-eng-early-17","level":"early","profession":"engineer","title":"The user's story in a bug advocacy","scenario":"You want a customer-reported bug fixed this sprint. Statistics alone haven't moved it. Tell the affected user's story — what they were trying to do and where it failed — to make it real.","task":"Write a 3-sentence advocacy that centers the affected user's experience.","tips":["Open with the user and their goal.","Show the moment it broke for them.","Tie their story to how many others hit the same wall."],"focus":["audience","impact"]},
    {"id":"narrative-eng-early-18","level":"early","profession":"engineer","title":"Framing a tradeoff as a choice, not a loss","scenario":"You're recommending you drop a rarely-used feature to simplify the codebase. Framed as 'removing something,' it sounds like loss. Framed as 'freeing capacity for what users actually use,' it's a gain.","task":"Rewrite the recommendation to frame the cut as a gain, honestly.","tips":["Lead with what's gained: speed, simplicity, focus.","Name the small loss honestly — don't pretend it's free.","Framing shapes reception without distorting the facts."],"focus":["impact","clarity"]},
    {"id":"narrative-eng-early-19","level":"early","profession":"engineer","title":"The 'imagine if' for a new tool","scenario":"You want the team to try a new observability tool. Persuade by painting the specific future where a past incident would have been caught in minutes instead of hours.","task":"Write a 2-3 sentence pitch anchored in a concrete 'if we'd had this' scenario.","tips":["Pick a real past incident everyone remembers.","Show how the tool would have shortened it.","Concrete counterfactuals beat feature lists."],"focus":["impact","structure"]},
    {"id":"narrative-eng-early-20","level":"early","profession":"engineer","title":"Persuading without authority","scenario":"You have no authority to mandate anything, but you want the team to adopt consistent error handling. Persuasion, not power, is your only lever. Build the case on shared benefit and one small first step.","task":"Write a 3-sentence pitch that persuades peers with no appeal to authority.","tips":["Appeal to shared pain and shared benefit.","Propose a small, low-risk first step, not a mandate.","Make saying yes easy and reversible."],"focus":["impact","audience"]},
    {"id":"narrative-eng-early-21","level":"early","profession":"engineer","title":"The strongest counterargument, stated fairly","scenario":"You're arguing for a rewrite, and the strongest counterargument is 'the current code works, don't touch it.' Stating that view fairly, then answering it, is more persuasive than strawmanning it.","task":"State the opposing view fairly, then give your honest rebuttal, in 3-4 sentences.","tips":["Put the counterargument in its strongest, fairest form.","Concede what's true in it.","Then show what it misses — the accumulating cost."],"focus":["impact","structure"]},
    {"id":"narrative-eng-early-22","level":"early","profession":"engineer","title":"The demo close that asks for something","scenario":"Your demo showed a promising prototype, but you end with a flat 'so that's it.' Persuasion needs a close: what you want the audience to do or decide next.","task":"Write a 2-sentence demo close that lands the value and makes a clear ask.","tips":["Restate the payoff in one line.","Make a specific ask: fund the next step, or try it.","A demo without an ask is a missed persuasion."],"focus":["impact","structure"],"placeholder":"So this cuts the import from minutes to seconds. If we like it, I'd need two more days to make it production-ready — can I take those?"},
    {"id":"narrative-eng-early-23","level":"early","profession":"engineer","title":"The stakes for a reluctant reviewer","scenario":"A senior keeps deprioritizing your PR. Instead of nagging, persuade by making the cost of the delay concrete to them: what's blocked, and the risk of the branch drifting.","task":"Write a 2-3 sentence nudge that makes the delay's cost concrete.","tips":["Name what the delay blocks downstream.","Mention the growing merge-conflict risk as the branch ages.","Give them a reason to prioritize, not just a reminder."],"focus":["impact","precision"]},
    {"id":"narrative-eng-early-24","level":"early","profession":"engineer","title":"The change narrative for a deprecation","scenario":"You're deprecating an internal API other teams use, and they'll resist. Persuade by framing the change around what they gain — a cleaner, supported replacement — and a smooth path there.","task":"Write a 3-4 sentence deprecation notice framed around the benefit and the path.","tips":["Lead with the better replacement, not the removal.","Give a clear, low-effort migration path.","Acknowledge the cost of moving, and shrink it."],"focus":["audience","impact"]},
    {"id":"narrative-eng-early-25","level":"early","profession":"engineer","title":"Making 'it depends' persuasive","scenario":"You're recommending a caching strategy where the honest answer is 'it depends on the traffic pattern.' A wishy-washy 'it depends' persuades no one. Turn it into a clear conditional recommendation.","task":"Write a recommendation that gives a clear default and the condition that changes it.","tips":["Give the default recommendation for the common case.","State the specific condition that would flip it.","A conditional with clear branches persuades; a shrug doesn't."],"focus":["impact","precision"]}
  ],
  "delivering-hard-messages": [
    {"id":"hard-eng-early-01","level":"early","profession":"engineer","title":"Telling the PM the feature will slip","scenario":"The feature the PM is counting on for a Friday launch won't be ready — you hit a problem that costs a week. Your instinct is to bury the bad news at the end after lots of context. Front-load it.","task":"Write a 2-3 sentence message that leads with the slip, then the reason and the new date.","tips":["Bad news first: it won't make Friday.","Then the reason, in one clause — no long runway.","End with the new date and what you're doing."],"focus":["clarity","impact"],"placeholder":"The search feature won't make Friday — the indexing is harder than scoped. Realistic date is next Wednesday; I'm on it now."},
    {"id":"hard-eng-early-02","level":"early","profession":"engineer","title":"The clean 'no' to extra scope","scenario":"A teammate asks you to also handle their part of a shared feature because they're busy. You can't take it on without dropping your own commitments. You need a clean no, not a maze of soft maybes.","task":"Write a clear, kind decline in two sentences.","tips":["Say no clearly in the first sentence.","Give the honest reason: it would drop your own commitment.","Offer what you can do instead, if anything."],"focus":["clarity","impact"]},
    {"id":"hard-eng-early-03","level":"early","profession":"engineer","title":"The behavior-impact-ask to a peer","scenario":"A teammate keeps merging without waiting for review, and it's caused two regressions. You need to raise it peer-to-peer. The clean structure is: the behavior, its impact, and a specific ask.","task":"Write the feedback in three sentences: behavior, impact, ask.","tips":["Describe the behavior factually, no character judgment.","State the concrete impact: two regressions this month.","Make one specific, doable ask."],"focus":["clarity","structure"],"placeholder":"The last two merges went in before review completed. Both caused regressions QA had to chase. Could you wait for at least one approval before merging?"},
    {"id":"hard-eng-early-04","level":"early","profession":"engineer","title":"Telling a senior their design has a flaw","scenario":"You've spotted a real problem in a senior engineer's design, and it's uncomfortable to say. Clear is kind: name the flaw directly and specifically rather than hinting around it.","task":"Write a respectful but direct message naming the flaw and why it matters.","tips":["Name the specific flaw, not a vague worry.","Say where it bites — the concrete failure case.","Respect and directness coexist; hinting helps no one."],"focus":["clarity","impact"]},
    {"id":"hard-eng-early-05","level":"early","profession":"engineer","title":"Admitting you introduced the bug","scenario":"A production bug traces back to your change from last week. You need to tell the team. The kind, clear move is to own it plainly, state the fix, and not drown it in self-flagellation.","task":"Write a 2-3 sentence message that owns the bug, states the fix, and moves forward.","tips":["Own it in one clean sentence.","State the fix and its status.","Skip the excessive apology — it helps no one."],"focus":["clarity","impact"]},
    {"id":"hard-eng-early-06","level":"early","profession":"engineer","title":"Declining a meeting you shouldn't be in","scenario":"You're invited to a recurring meeting that isn't a good use of your time, but the organizer is senior and you don't want to seem uncommitted. A clear, respectful decline is kinder than silent disengagement.","task":"Write a two-sentence decline that's respectful and gives a real reason.","tips":["Decline clearly, don't just go quiet and skip it.","Give the honest reason: your time is better spent elsewhere.","Offer to stay looped in via notes if relevant."],"focus":["clarity","concision"]},
    {"id":"hard-eng-early-07","level":"early","profession":"engineer","title":"Telling QA the fix didn't work","scenario":"QA verified a fix as done, but you've found it only masked the problem, which will resurface. You have to reopen it and tell them the good news was premature. Front-load the correction clearly.","task":"Write a 2-3 sentence message that clearly states the fix is incomplete and why.","tips":["Lead with the correction: the fix isn't complete.","Explain briefly what it actually did versus what's needed.","Own the miscommunication if it was yours."],"focus":["clarity","precision"]},
    {"id":"hard-eng-early-08","level":"early","profession":"engineer","title":"Pushing back on an unrealistic deadline","scenario":"Your manager set a deadline you're confident you can't hit honestly. Staying silent and missing it later is worse than saying so now. Deliver the hard message clearly, with what's actually achievable.","task":"Write a 2-3 sentence message that says the deadline isn't achievable and offers what is.","tips":["Say plainly the date isn't realistic — early, not later.","Give the honest achievable date.","Offer a scope cut that could hit the original date."],"focus":["clarity","impact"]},
    {"id":"hard-eng-early-09","level":"early","profession":"engineer","title":"The 'I'm blocked and it's serious' escalation","scenario":"You've been blocked for two days waiting on another team and it's now threatening your deadline. You've been too polite to escalate. The kind thing for everyone is to state the blockage and its cost clearly.","task":"Write a 2-3 sentence escalation that states the block, its cost, and what you need.","tips":["State the block and how long it's lasted.","Name the cost: the deadline it now threatens.","Make the specific ask that unblocks you."],"focus":["clarity","impact"],"placeholder":"I've been blocked two days on the auth-team dependency, and it's now going to push my deadline. Could someone there prioritize the API grant, or tell me who can?"},
    {"id":"hard-eng-early-10","level":"early","profession":"engineer","title":"Rejecting a PR that isn't ready","scenario":"A teammate's PR has fundamental problems and shouldn't merge, but you don't want to discourage them. Clear-is-kind means an honest 'not yet' with specifics, not a vague approval that wastes everyone's time.","task":"Write a review verdict that clearly declines the merge and gives the path to yes.","tips":["State clearly it's not ready to merge.","Give the two or three specific blockers.","Frame it as a path to approval, not a rejection of them."],"focus":["clarity","structure"]},
    {"id":"hard-eng-early-11","level":"early","profession":"engineer","title":"Telling your manager you're overloaded","scenario":"You've been assigned more than you can deliver well, and quality is starting to slip. The hard message is admitting the overload before something breaks, with a concrete ask about priorities.","task":"Write a 2-3 sentence message that names the overload and asks for a priority call.","tips":["State the situation factually: more than you can do well.","Don't frame it as personal failure — it's a capacity fact.","Ask them to help prioritize, with a specific tradeoff."],"focus":["clarity","impact"]},
    {"id":"hard-eng-early-12","level":"early","profession":"engineer","title":"The 'this approach won't scale' to a peer","scenario":"A teammate is proud of an approach that works now but will break at higher load. Telling them is awkward. Clear is kind: name the scaling limit specifically and early, before it's built on.","task":"Write a 2-3 sentence message that names the scaling problem directly and helpfully.","tips":["Acknowledge what works about it now.","Name the specific point where it breaks: the load threshold.","Offer to pair on the alternative."],"focus":["clarity","precision"]},
    {"id":"hard-eng-early-13","level":"early","profession":"engineer","title":"Correcting a teammate's wrong claim publicly","scenario":"In a channel, a teammate confidently stated something technically wrong that others may act on. You need to correct it without embarrassing them. Direct on the fact, gentle on the person.","task":"Write a 2-sentence correction that's clear on the fact and kind to the person.","tips":["Correct the fact plainly — others need the right info.","Keep it about the fact, not their competence.","A light 'small correction' framing softens without hedging the fact."],"focus":["clarity","audience"]},
    {"id":"hard-eng-early-14","level":"early","profession":"engineer","title":"Telling the PM a requested feature is a bad idea","scenario":"The PM wants a feature you think will confuse users and add real complexity. Going along quietly isn't kind. Deliver the concern clearly, with your reasoning, while respecting that it's their call.","task":"Write a 3-sentence message that states your concern, the reason, and defers the decision appropriately.","tips":["State the concern directly, not as a timid question.","Give the specific reason it worries you.","Acknowledge it's their call — you're giving them your read."],"focus":["clarity","impact"]},
    {"id":"hard-eng-early-15","level":"early","profession":"engineer","title":"The honest incident-cause admission","scenario":"Writing the incident review, the honest root cause is that you skipped a step you knew you should do. It's tempting to soften it. A blameless-but-honest account serves the team better.","task":"Write the root-cause line honestly, owning the skipped step without drama.","tips":["State what was skipped, factually.","Frame it systemically: why the step was easy to skip.","Honesty here makes the prevention real."],"focus":["clarity","precision"]},
    {"id":"hard-eng-early-16","level":"early","profession":"engineer","title":"Saying you disagree with the team decision","scenario":"The team decided on an approach you think is wrong, but the discussion has moved on. Raising your disagreement now is uncomfortable. If it matters, say it clearly rather than quietly complying and resenting it.","task":"Write a 2-3 sentence message that voices the disagreement clearly and constructively.","tips":["State that you see it differently, and why, briefly.","Offer it as input, not obstruction.","If overruled, commit — but voice it first, clearly."],"focus":["clarity","impact"]},
    {"id":"hard-eng-early-17","level":"early","profession":"engineer","title":"Telling a teammate their code broke yours","scenario":"A teammate's merge broke your feature branch and cost you an hour. You need to flag it without sounding accusatory. Behavior, impact, ask — keep it factual and forward-looking.","task":"Write a 2-3 sentence message: what happened, the impact, the ask.","tips":["State the factual event, not blame.","Note the impact briefly.","Ask for the specific thing that avoids a repeat."],"focus":["clarity","structure"]},
    {"id":"hard-eng-early-18","level":"early","profession":"engineer","title":"The 'I can't finish this today' heads-up","scenario":"You committed to finishing something today and now you can't. The kind move is the early heads-up, not the silent slip discovered at end of day. Front-load it with the new plan.","task":"Write a two-sentence heads-up that states the slip and the new plan, sent early.","tips":["Send it as soon as you know, not at 5pm.","State plainly it won't be done today.","Give the new time and any impact on others."],"focus":["clarity","concision"],"placeholder":"Heads-up: I won't finish the export fix today after all — hit a snag with the file encoding. I'll have it first thing tomorrow."},
    {"id":"hard-eng-early-19","level":"early","profession":"engineer","title":"Declining to cut a corner you were asked to cut","scenario":"Under deadline pressure, someone asks you to ship without handling a known security case. You need to refuse clearly while being constructive about the real deadline pressure they're feeling.","task":"Write a 2-3 sentence response that declines the corner-cut and addresses the pressure.","tips":["Say no to shipping the unsafe version, clearly.","Name the specific risk you won't take on.","Offer a real alternative to the deadline pressure."],"focus":["clarity","impact"]},
    {"id":"hard-eng-early-20","level":"early","profession":"engineer","title":"Telling your buddy the intern's PR needs work","scenario":"You're reviewing the intern you're buddying, and their PR has a lot wrong with it. Too-gentle feedback won't help them grow; too-harsh will crush them. Be clear and specific, and separate the big things from the small.","task":"Write review feedback that's honest about the main issues while encouraging, in 3-4 sentences.","tips":["Lead with the one or two things that actually matter.","Be specific — vague praise or vague criticism both fail them.","Note what they did well, briefly and genuinely."],"focus":["clarity","audience"]},
    {"id":"hard-eng-early-21","level":"early","profession":"engineer","title":"The 'we need to roll back your feature' message","scenario":"A feature a teammate shipped is causing problems and needs to be rolled back. Telling them is awkward, especially if they're proud of it. Front-load the decision, keep it about the data, not the person.","task":"Write a 2-3 sentence message that states the rollback, the reason, and the next step.","tips":["State the rollback decision first, plainly.","Give the data-based reason, not a judgment.","Frame the next step as fixing forward together."],"focus":["clarity","impact"]},
    {"id":"hard-eng-early-22","level":"early","profession":"engineer","title":"Admitting you don't understand the codebase yet","scenario":"You've been assigned work in a part of the system you don't understand well, and pretending otherwise will cost more later. The hard but kind message is admitting it and asking for a proper ramp-up.","task":"Write a two-sentence message that admits the gap and asks for what you need.","tips":["State plainly you're not up to speed on this area yet.","There's no shame in it early-career — pretending is the risk.","Ask for the specific help: a walkthrough, a doc, a pairing hour."],"focus":["clarity","impact"]},
    {"id":"hard-eng-early-23","level":"early","profession":"engineer","title":"The estimate that has to grow","scenario":"You already gave an estimate, and now you know it was too low by half. Delaying the update makes it worse. Deliver the revised estimate clearly, with what you learned, before the old one is relied on further.","task":"Write a 2-3 sentence update that revises the estimate and explains what changed.","tips":["Lead with the revised number, plainly.","Explain what you learned that moved it.","Deliver it as soon as you know, not at the old deadline."],"focus":["clarity","precision"],"placeholder":"I need to revise my estimate up — it's closer to two weeks than one. The shared-validation code touches more services than I'd seen when I first scoped it."},
    {"id":"hard-eng-early-24","level":"early","profession":"engineer","title":"Telling someone their request has to wait","scenario":"A teammate urgently wants your help, but you're mid-incident and can't context-switch. Saying 'not now' clearly, with when you can, is kinder than a distracted half-help or silence.","task":"Write a two-sentence reply that declines for now and gives a real when.","tips":["Say clearly you can't right now, and briefly why.","Give a specific time you can help.","A clear 'not now, but at 3' beats a vague 'soon'."],"focus":["clarity","concision"]},
    {"id":"hard-eng-early-25","level":"early","profession":"engineer","title":"The retro feedback about a teammate's pattern","scenario":"In the retro you want to raise that a teammate's habit of large, last-minute PRs stresses the whole review process. It's sensitive. Frame it as a pattern and its impact, with a concrete ask, not a personal attack.","task":"Write retro feedback in 3-4 sentences: the pattern, its impact, and a proposed change.","tips":["Describe the pattern without naming it as one person's fault.","State the team-level impact: rushed reviews, missed issues.","Propose a concrete change: smaller, earlier PRs."],"focus":["clarity","structure"]}
  ],
  "putting-it-together": [
    {"id":"together-eng-early-01","level":"early","profession":"engineer","title":"The incident update that does everything at once","scenario":"You're posting a mid-incident update to a channel with engineers and non-engineers watching. It needs to lead with status, be precise about what you know, stay calm, and end with the next update time — all in a few lines.","task":"Write a 3-4 line incident update that leads with status, is precise, and states the next update.","tips":["Status first, in plain language for the mixed audience.","Be precise about what's confirmed vs. suspected.","End with the next-update time so nobody has to ask."],"focus":["structure","clarity"],"placeholder":"Sign-in is failing for ~20% of users since 3:10pm. Cause looks like the token-refresh deploy; rolling back now. Next update by 3:30."},
    {"id":"together-eng-early-02","level":"early","profession":"engineer","title":"The PR description that reviews clean","scenario":"You're writing a PR description for a non-trivial change. It should lead with the what and why, give an outside reviewer enough context, flag the risky part, and cut anything the diff already shows.","task":"Write a complete PR description that does all four in under six lines.","tips":["Open with what changed and why it matters.","One line of context for a reviewer new to the area.","Point to the risky part of the diff; cut the rest."],"focus":["structure","clarity"]},
    {"id":"together-eng-early-03","level":"early","profession":"engineer","title":"The standup that respects everyone's time","scenario":"Your standup update has to be tight, lead with outcomes, name a real blocker, and be answerable — all in 20 seconds. Pull together concision, structure, and a clear ask.","task":"Write a 20-second standup update: outcome, today's focus, blocker or none.","tips":["Lead with yesterday's outcome, not activity.","One sentence on today's main thing.","Name the blocker precisely or say 'none' — no filler."],"focus":["concision","structure"],"placeholder":"Shipped the retry fix yesterday. Today: wiring up the export endpoint. Blocked on the staging DB access — need infra to grant it."},
    {"id":"together-eng-early-04","level":"early","profession":"engineer","title":"The Slack ask to a busy senior","scenario":"You need 30 minutes of a senior's time on a tricky problem. The message must lead with the ask, give just enough context, respect their time, and make yes easy — register matched to a quick Slack DM.","task":"Write the DM: clear ask, minimal context, two time options.","tips":["Ask first, context second, in Slack-appropriate brevity.","Two sentences of context maximum.","Offer two slots so replying is one click."],"focus":["concision","clarity"]},
    {"id":"together-eng-early-05","level":"early","profession":"engineer","title":"The bug report a stranger can act on","scenario":"You're filing a bug that someone on another team will pick up. It needs impact first, precise repro steps, the environment, and no assumed context — a complete, self-contained report.","task":"Write a bug report that leads with impact and gives precise, context-free repro steps.","tips":["Impact first: who's affected and how badly.","Numbered repro steps a stranger can follow exactly.","State environment and version; assume no shared context."],"focus":["structure","precision"]},
    {"id":"together-eng-early-06","level":"early","profession":"engineer","title":"The release note for a mixed public","scenario":"You're writing a release note read by customers and internal staff. It should lead with the user benefit, be precise about what changed, match a public register, and skip internals — all in two or three lines.","task":"Write a release note that leads with user benefit, is precise, and reads for a public audience.","tips":["Open with what the user can now do.","Be specific about the improvement, in their terms.","Keep the register public — no internal jargon."],"focus":["audience","clarity"]},
    {"id":"together-eng-early-07","level":"early","profession":"engineer","title":"The estimate email that holds up","scenario":"Your manager asked for an estimate to forward upward. It must give the number first, state assumptions, be honest about uncertainty, and read cleanly for a reader you can't see — pull it all together.","task":"Write the estimate email: number first, assumptions, one honest caveat.","tips":["Lead with the estimate — that's the answer they need.","List the two or three assumptions it rests on.","One caveat, honestly stated; it may be read up the chain."],"focus":["precision","structure"]},
    {"id":"together-eng-early-08","level":"early","profession":"engineer","title":"The on-call handoff that stands alone","scenario":"Your on-call handoff has to lead with what needs watching, be precise about thresholds and commands, work for someone half-asleep, and cut the noise — a complete handoff under real constraints.","task":"Write a handoff that leads with the watch item, is precise, and needs no context.","tips":["Lead with the one thing they must watch tonight.","Exact thresholds and commands — no 'the usual way'.","Write for the tired stranger, and cut everything else."],"focus":["structure","precision"],"placeholder":"Watch: logging-cluster disk alert, likely to fire ~2am. If it does: run `clear-old-logs.sh`, confirm usage drops below 80%. Everything else was quiet."},
    {"id":"together-eng-early-09","level":"early","profession":"engineer","title":"The design-doc comment that lands","scenario":"You're leaving a substantive comment on a design doc. It must lead with your main point, own a clear position, be precise about the concern, and stay respectful — integrating several skills at once.","task":"Write a design-doc comment that leads with the concern, takes a position, and is precise.","tips":["Lead with the main concern, not warm-up questions.","Own a position rather than hinting.","Be precise about where the concern bites."],"focus":["structure","impact"]},
    {"id":"together-eng-early-10","level":"early","profession":"engineer","title":"The demo intro for a mixed room","scenario":"You're opening a sprint demo to engineers, a PM, and a designer. The intro must pick a primary audience, lead with the user benefit, set up a before/after, and stay brief — everything together in two sentences.","task":"Write a two-sentence demo intro that picks an audience and leads with the payoff.","tips":["Choose the primary listener deliberately.","Lead with the user-visible payoff.","Set up the before/after in one clause."],"focus":["audience","impact"]},
    {"id":"together-eng-early-11","level":"early","profession":"engineer","title":"The 'bad news' status to your manager","scenario":"Your weekly status includes a slip, a risk, and one win. It must front-load the bad news, be precise, keep composure, and end with what you need — all in a scannable shape.","task":"Write a status update that front-loads the slip, is precise, and ends with an ask.","tips":["Bad news first, stated plainly and calmly.","Precise on dates and impact.","Close with the specific decision or help you need."],"focus":["structure","impact"]},
    {"id":"together-eng-early-12","level":"early","profession":"engineer","title":"The cross-team request that gets a yes","scenario":"You need another team to prioritize a change for you. The message must lead with the ask, translate into their stakes, be precise about what and by when, and stay brief — the whole toolkit in one message.","task":"Write the request: ask first, framed in their stakes, precise on what and when.","tips":["Ask first, then why it matters to them.","Be precise: exactly what you need and by when.","Keep it short enough to answer between meetings."],"focus":["audience","clarity"]},
    {"id":"together-eng-early-13","level":"early","profession":"engineer","title":"The postmortem summary line","scenario":"You're writing the one-paragraph summary at the top of a postmortem, read by people who won't read the rest. It must state impact, cause, and fix precisely, blamelessly, and briefly — everything distilled.","task":"Write a 3-4 sentence postmortem summary: impact, cause, fix, prevention.","tips":["Impact first: what users experienced and for how long.","Cause and fix, precise and blameless.","One line on what prevents a recurrence."],"focus":["structure","precision"],"placeholder":"For 35 minutes, ~20% of sign-ins failed. A deploy changed the token-refresh path; we rolled it back. We're adding a canary check to catch this class of bug before full rollout."},
    {"id":"together-eng-early-14","level":"early","profession":"engineer","title":"The 'I disagree' message done well","scenario":"You need to disagree with a decision, up the ladder, in writing. It must be direct about the disagreement, precise about the reason, respectful in register, and end constructively — the hard-message and presence skills together.","task":"Write a 3-4 sentence disagreement that's direct, precise, respectful, and constructive.","tips":["State the disagreement clearly, no hedging.","Give the precise reason it concerns you.","End with a constructive path, and defer if it's their call."],"focus":["impact","clarity"]},
    {"id":"together-eng-early-15","level":"early","profession":"engineer","title":"The commit that documents itself","scenario":"You're writing a commit for a subtle fix. The subject must be a tight imperative line, and the body must precisely explain what, why, and what to watch — concision and precision together, for a future reader.","task":"Write a commit subject and body: tight subject, precise what/why/watch body.","tips":["Subject: imperative, under ten words.","Body: what changed, why, and the edge case to retest.","Write for the confused reader six months out."],"focus":["concision","precision"]},
    {"id":"together-eng-early-16","level":"early","profession":"engineer","title":"The feature flag rollout announcement","scenario":"You're announcing a flagged rollout to a channel of engineers and support. It must lead with what's changing for users, be precise about the schedule, tell support what to expect, and stay brief.","task":"Write a rollout announcement: user impact, precise schedule, note to support.","tips":["Lead with what users will notice, and when.","Precise percentages and dates.","One line telling support what tickets to expect."],"focus":["audience","precision"]},
    {"id":"together-eng-early-17","level":"early","profession":"engineer","title":"The answer under pressure, structured","scenario":"In a review meeting a senior fires a pointed question about your approach. Your spoken answer must address the actual question first, be precise, stay composed, and have a clear shape — pressure and structure together.","task":"Write the spoken answer: direct response first, then a two-point structured reason.","tips":["Answer the actual question in the first sentence.","Follow with two precise reasons, signposted.","Stay composed; structure signals control."],"focus":["structure","clarity"]},
    {"id":"together-eng-early-18","level":"early","profession":"engineer","title":"The onboarding doc section","scenario":"You're writing a section of the team onboarding doc. It must assume no context, be precisely actionable, organized into clear steps, and cut anything a newcomer doesn't need yet — audience and structure together.","task":"Write an onboarding section that assumes no context and gives precise, ordered steps.","tips":["Spell out every internal name on first use.","Order the steps as the newcomer will hit them.","Cut anything not needed in the first week."],"focus":["audience","structure"]},
    {"id":"together-eng-early-19","level":"early","profession":"engineer","title":"The 'here's my recommendation' writeup","scenario":"After evaluating three options, you're writing a recommendation for the team. It must lead with your pick, own it, structure the comparison, be precise about tradeoffs, and pre-empt the main objection.","task":"Write a recommendation writeup: pick first, one governing reason, main objection answered.","tips":["Lead with the recommendation and own it.","Give the governing reason, then the structured tradeoffs.","Name and answer the strongest objection."],"focus":["impact","structure"]},
    {"id":"together-eng-early-20","level":"early","profession":"engineer","title":"The 'I broke it' incident message, complete","scenario":"Your change caused an incident. The message must own it plainly, lead with status and ETA, be precise about impact, stay composed, and tell people what to do — all under live pressure.","task":"Write a 3-4 line message: own it, status, ETA, precise impact, what others should do.","tips":["Own it in one clean sentence, then status and ETA.","Be precise about who's affected.","Tell others exactly what to do or not do meanwhile."],"focus":["clarity","impact"],"placeholder":"My migration wiped staging seed data — QA, please hold. Restore is running, back in ~30 min. No production impact."},
    {"id":"together-eng-early-21","level":"early","profession":"engineer","title":"The reviewer feedback for the intern, whole","scenario":"You're giving the intern review feedback. It must lead with what matters most, be precise and actionable, match a supportive register, separate blockers from nits, and encourage — several skills at once.","task":"Write intern review feedback: main issue first, precise fixes, one genuine positive.","tips":["Lead with the one or two things that matter.","Precise, actionable fixes — not vague direction.","One genuine positive; separate blockers from nits."],"focus":["audience","structure"]},
    {"id":"together-eng-early-22","level":"early","profession":"engineer","title":"The scope-change heads-up to the PM","scenario":"You discovered the ticket is bigger than scoped. The message must lead with the new size, be precise about why, translate into the PM's schedule stakes, and offer a choice — audience, precision, and impact together.","task":"Write a heads-up: new size first, precise reason, schedule impact, a choice.","tips":["Lead with the revised size, plainly.","Precise on what makes it bigger.","Frame it as a choice with a clear tradeoff."],"focus":["audience","impact"],"placeholder":"This ticket is closer to three days than one — it touches the shared validation library used by six services. I can do the safe full fix, or a scoped patch that risks the other services; your call."},
    {"id":"together-eng-early-23","level":"early","profession":"engineer","title":"The runbook step, production-grade","scenario":"You're writing a runbook step that must work for a stranger at 2am: precise commands, clear success criteria, no assumed context, and cut to the essential — precision, audience, and concision together.","task":"Write a runbook step with exact commands, a precise success check, and no assumed context.","tips":["Exact command, copy-pasteable.","Define success with a number or comparison.","Write for the tired first-timer; cut everything else."],"focus":["precision","audience"]},
    {"id":"together-eng-early-24","level":"early","profession":"engineer","title":"The 'why we should do this' proposal","scenario":"You're proposing a small improvement to the team. It must lead with one governing claim, structure the case, make the stakes concrete, be precise about cost, and end with a clear ask — the full toolkit in one short doc.","task":"Write a short proposal: governing claim, concrete stakes, precise cost, clear ask.","tips":["One governing claim up front.","Make the stakes concrete and the cost precise.","End with a specific, easy-to-approve ask."],"focus":["structure","impact"]},
    {"id":"together-eng-early-25","level":"early","profession":"engineer","title":"The end-of-week note, edited like a reader","scenario":"Your Friday note to your manager needs to lead with outcomes, be scannable, precise, honest about one risk, and short enough to read in ten seconds. Then edit it once more as the reader would.","task":"Write the Friday note, then trim it as your manager would read it: outcomes, one risk, scannable.","tips":["Outcomes first, in a one-line headline.","Scannable labels: shipped, in progress, risk.","Then cut a third — read it as the busy reader would."],"focus":["concision","structure"],"placeholder":"Headline: rate-limiter shipped, search on track for next week. Shipped: rate-limiter + two checkout fixes. Risk: search depends on the auth change landing Monday."}
  ],
};
